import { G, T, A, O, P } from './domains.js';

export const part5 = [
  {id:505,domain:G,question:"What is a rainbow table?",options:["A visual dashboard displaying color-coded security metrics, risk indicators, and compliance status using charts and graphs for executive briefings and security program reporting","A precomputed table of password hashes mapping hash values back to plaintext, enabling fast password cracking without computing hashes in real-time","An encryption scheme that applies multiple independent cipher transformations across several data dimensions simultaneously to increase the overall complexity and strength of the encryption","A reference table containing cryptographic key material organized by key identifier, algorithm type, and rotation schedule for use in key management infrastructure operations"],answer:1,explanation:"Rainbow tables enable fast reverse hash lookups — defeated by salting (adding unique random values to each password before hashing makes precomputation impractical).",optionExplanations:["Security metric dashboards are reporting tools using multiple colors; rainbow tables are precomputed hash-to-plaintext lookup structures used by attackers to crack password hashes rapidly.","A rainbow table precomputes hash→password mappings, allowing an attacker with stolen hashes to look up passwords instantly rather than computing hashes for each guess.","Multi-dimensional encryption describes layered cipher approaches; rainbow tables are specifically precomputed hash-to-plaintext lookup tables, not an encryption scheme or cipher construction.","Key management reference tables organize cryptographic keys; rainbow tables contain precomputed hash values mapped back to the plaintext passwords that produced them for fast password recovery."]},
  {id:506,domain:O,question:"What is the purpose of an emergency response plan?",options:["A comprehensive organizational continuity document addressing only natural disaster threat categories such as earthquakes, floods, hurricanes, and wildfires, excluding other disruptive event types","Documented procedures for responding to various emergency scenarios (natural disaster, cyberattack, power failure, pandemic) to minimize impact and enable rapid recovery","A detailed building-specific emergency egress document specifying evacuation routes, exit locations, assembly areas, floor warden assignments, and occupant headcount procedures for fire emergencies","A pre-defined communication protocol specifying how IT staff, management, and end users are notified and kept informed during system outages or significant service degradations"],answer:1,explanation:"Emergency response plans define roles, communication trees, decision authorities, and action steps for multiple scenarios — integrating with BCP and DRP for comprehensive resilience.",optionExplanations:["Natural disasters are one emergency category; emergency response plans cover all major disruptive events including cyberattacks, power failures, pandemics, and any other scenario requiring coordinated response.","Emergency response plans document who does what, who communicates with whom, who makes decisions, and the specific steps for each emergency type — enabling coordinated response under stress.","Fire evacuation plans are a physical safety subset of emergency response; the broader emergency response plan covers cyberattacks, power failures, pandemics, and all other disruptive scenarios.","IT outage communication plans are a subset of emergency response; the full plan covers all crisis types including decision authority, resource coordination, and recovery actions across all scenarios."]},
  {id:507,domain:T,question:"What is pharming?",options:["Cyberattacks specifically targeting agricultural infrastructure such as precision farming equipment, irrigation control systems, and food supply chain management software systems","Redirecting users to fraudulent websites without their knowledge by corrupting DNS settings or hosts files, making the attack transparent to the victim","Systematically collecting and aggregating personal information from social media platforms by scraping public profiles and relationship graphs for intelligence gathering or fraud enablement","Outsourcing cybercriminal operations by contracting specialized attack services, exploit development, and malicious infrastructure management to criminal organizations on underground marketplaces"],answer:1,explanation:"Unlike phishing, pharming doesn't require a malicious link — victims type the legitimate URL but DNS corruption or hosts file modification sends them to an attacker's site.",optionExplanations:["Agricultural infrastructure attacks are a critical infrastructure threat; pharming is a web-based attack redirecting users to fraudulent sites through DNS corruption or hosts file modification.","Pharming corrupts DNS resolution (DNS poisoning) or modifies local hosts files so that typing a legitimate domain resolves to an attacker's IP, serving a convincing fake site.","Social media data scraping is data harvesting for OSINT or fraud; pharming is a web redirection attack that corrupts DNS or hosts files so legitimate domains resolve to fraudulent sites.","Outsourcing criminal operations is crime-as-a-service; pharming is a specific technical attack on DNS resolution that silently redirects victim web requests to attacker-controlled fraudulent sites."]},
  {id:508,domain:A,question:"What is data masking?",options:["Concealing observable network traffic patterns using traffic padding, timing randomization, or cover traffic to prevent adversaries from performing traffic flow analysis attacks","Replacing real data with realistic but fictional data to protect sensitive information while maintaining its usability for testing, development, or analytics","Applying symmetric or asymmetric encryption algorithms to data before it is written to storage media to render the content unreadable to anyone without the decryption key","Irreversibly removing or generalizing all personally identifiable attributes from a dataset to ensure that no individual can be re-identified before the data is publicly released"],answer:1,explanation:"Data masking enables realistic development/testing with production-like data without exposing real PII or sensitive information — required for compliance in dev/test environments.",optionExplanations:["Network traffic pattern obfuscation is traffic analysis prevention; data masking transforms data field values to substitute real sensitive values with realistic but fictional replacement values.","Data masking substitutes real values (names, SSNs, credit card numbers) with plausible but fictitious equivalents — 'John Smith' becomes 'Mary Johnson' — preserving format while removing real PII.","Encryption makes data unreadable but retains the original value recoverable with a key; masking replaces real values with different realistic-looking fictional values that preserve format.","Anonymization permanently removes identifying information with the intent of irreversibility; masking can be reversible and creates datasets that look real but substitute fictitious values for PII."]},
  {id:509,domain:T,question:"What is a Denial-of-Service (DoS) attack's primary goal?",options:["Exfiltrating sensitive files, records, and intellectual property from a target system by exploiting application vulnerabilities or misconfigured storage access controls to extract data","Making a resource unavailable to legitimate users by overwhelming it with traffic or requests, exploiting vulnerabilities to crash it, or disrupting connectivity","Exploiting unpatched software vulnerabilities, stolen credentials, or misconfigured access controls to breach security perimeters and gain unauthorized interactive access to systems or accounts","Positioning an attacker between two communicating parties to eavesdrop on, record, or modify network traffic without authorization, targeting confidentiality and message integrity"],answer:1,explanation:"DoS attacks target availability — the 'A' in CIA triad. Success is measured by downtime duration and impact on business operations and reputation.",optionExplanations:["Data exfiltration is a confidentiality attack targeting data theft; DoS attacks target availability by denying service to legitimate users without necessarily gaining access to or stealing data.","DoS attacks deny service — flooding network links, exhausting server resources, exploiting bugs that crash services, or corrupting data — all with the goal of preventing legitimate access.","Gaining unauthorized access is an integrity and confidentiality attack enabling further compromise; DoS attacks target availability by disrupting service to legitimate users without requiring system access.","Communication interception is a man-in-the-middle attack targeting confidentiality; DoS attacks target availability by making resources unreachable rather than intercepting or stealing communications."]},
  {id:510,domain:G,question:"What is cryptanalysis?",options:["An academic discipline focused on reviewing and summarizing published cryptography research papers, textbooks, and conference proceedings to teach students the mathematical history of ciphers","The study and practice of analyzing cryptographic systems to find weaknesses and recover plaintext without the key","The field of applied cryptography concerned with designing, mathematically proving security properties of, and standardizing new encryption algorithms, hash functions, and protocols","A malware reverse engineering technique that analyzes obfuscated or packed malicious executable samples to understand their behavior, payloads, and command infrastructure"],answer:1,explanation:"Cryptanalysis attacks include brute force, differential cryptanalysis, linear cryptanalysis, birthday attacks, and side-channel attacks — all aimed at defeating cryptographic security.",optionExplanations:["Academic study of cryptography literature is cryptology education; cryptanalysis is an active discipline of breaking or finding exploitable weaknesses in real cryptographic systems and implementations.","Cryptanalysis studies mathematical properties, implementation flaws, and physical side-channels to find faster-than-brute-force methods to defeat cryptography.","Creating new algorithms is the design side of cryptography; cryptanalysis specifically evaluates and attempts to break existing cryptographic systems through mathematical and implementation analysis.","Malware analysis is threat intelligence and incident response work; cryptanalysis focuses on finding mathematical or implementation weaknesses in cryptographic algorithms to defeat encryption without the key."]},
  {id:511,domain:O,question:"What is a security information sharing community's purpose?",options:["Establishing formal personnel exchange and staff rotation programs between organizations to share cybersecurity talent and specialized expertise across organizational and sector boundaries","Enabling organizations within the same sector to share threat intelligence, IoCs, and best practices to improve collective defensive capabilities","An online discussion forum, professional conference series, or certification association where cybersecurity practitioners network, share research presentations, and exchange career development resources","A government-administered program that collects and distributes classified threat intelligence derived from signals intelligence and law enforcement sources to vetted private sector recipients"],answer:1,explanation:"ISACs (Information Sharing and Analysis Centers), ISAO, and private threat sharing communities help defenders benefit from each other's experiences before they're targeted.",optionExplanations:["Staff sharing programs are HR and talent collaboration arrangements; security information sharing communities exchange threat intelligence, IoCs, and defensive best practices for collective security improvement.","Information sharing communities (FS-ISAC, H-ISAC, MS-ISAC) distribute anonymized threat intelligence — if a bank detects a new attack pattern, sharing it helps other banks defend before being hit.","Professional networking forums are community and education platforms; ISACs and similar sharing communities are operational threat intelligence exchange mechanisms with direct defensive application value.","Government intelligence sharing programs like InfraGard exist; the broader information sharing ecosystem includes ISACs and private sector sharing without requiring government involvement or security clearances."]},
  {id:512,domain:T,question:"What is credential spraying?",options:["Using a compromised set of stolen credentials to authenticate sequentially to multiple different systems and services across an organization in order to expand attacker access","An attack using a small number of common passwords against many accounts to avoid lockout thresholds, rather than testing many passwords against one account","Intercepting and capturing authentication credential hashes transmitted over wireless networks by performing passive monitoring of WPA Enterprise RADIUS authentication exchanges","A SQL injection variant that inserts stolen username and password values directly into database authentication query strings to bypass application-layer login form validation"],answer:1,explanation:"Credential spraying avoids account lockouts — instead of 100 attempts on one account (which locks it), try 'Password1!' across 100 different accounts.",optionExplanations:["Using stolen credentials across multiple systems is lateral movement using credential reuse; spraying inverts the brute-force approach by trying few passwords against many different accounts.","Credential spraying inverts the brute force approach — it tries one or few passwords (common ones like 'Spring2024!') against all accounts, staying under lockout thresholds while covering maximum accounts.","Wireless credential capture is a network-level attack; credential spraying is an authentication attack pattern testing a small number of common passwords across many accounts to avoid lockout.","SQL injection using credential data is an application injection attack; credential spraying is an authentication brute-force technique testing common passwords across many accounts at low per-account frequency."]},
  {id:513,domain:A,question:"What is an intrusion detection system (IDS) anomaly detection mode?",options:["Matching observed network traffic patterns and system activity against a database of pre-defined attack signatures and indicators of compromise for known malware and exploits","Establishing a baseline of normal behavior and alerting on statistical deviations, enabling detection of novel attacks without known signatures","Identifying unusual physical behavior in computer hardware components such as unexpected temperature spikes, power consumption anomalies, or firmware integrity failures on endpoints","Permitting only network traffic matching a pre-defined allowlist of approved source addresses, destination ports, and protocols while blocking all non-conforming traffic"],answer:1,explanation:"Anomaly-based detection catches zero-days and insider threats that have no signatures — at the cost of higher false positive rates when legitimate behavior deviates from the baseline.",optionExplanations:["Signature-based detection matches known attack patterns; anomaly detection baselines normal behavior and alerts on statistical deviations, enabling detection of novel attacks without existing signatures.","Anomaly-based IDS learns what normal looks like (traffic volume, protocol distribution, user behavior) and alerts when observed behavior deviates significantly from that baseline.","Hardware anomaly monitoring is a physical and firmware security domain; IDS anomaly detection specifically analyzes network traffic or system software behavior for statistical deviations from baseline.","Allowlist-based traffic control is network access control; anomaly detection measures statistical deviation from an established behavioral baseline, not binary matching against a known-good allowlist."]},
  {id:514,domain:P,question:"What is the storage limitation principle in data privacy?",options:["Setting a maximum data volume or storage quota that restricts the total quantity of information that can be retained about any single identified individual data subject","Personal data should be kept in identifiable form only as long as necessary for the purpose it was collected — then deleted or anonymized","Requiring that all personal data be maintained within a single designated central database or repository rather than distributed across multiple systems, locations, or cloud environments","Mandating that all personal data must be stored and processed exclusively on internal on-premises infrastructure, prohibiting use of any external cloud storage or processing services"],answer:1,explanation:"GDPR Article 5(1)(e) mandates storage limitation — customer purchase data needed for 7-year tax compliance must be deleted at 7 years, not kept indefinitely.",optionExplanations:["Data volume quotas per person are storage capacity constraints; storage limitation addresses how long personal data may be retained in identifiable form, not how much can be stored.","Storage limitation means defining and enforcing retention periods for each data category — keeping data longer than necessary creates legal liability and increases breach exposure.","Centralizing data to a single location is data architecture governance; storage limitation concerns the duration of retention in identifiable form, not the number of storage systems used.","Restricting processing to on-premises infrastructure is a data residency requirement; storage limitation addresses the duration personal data may be kept in identifiable form regardless of storage location."]},
  {id:515,domain:G,question:"What is a digital signature?",options:["A legally recognized electronic signature method that may consist of a typed name, a checkbox click, or a click-to-sign button indicating intent to be bound by a document","A cryptographic mechanism using the signer's private key to create a verification code attached to a message, allowing recipients to verify both the sender's identity and message integrity","A digitized bitmap image created by scanning or photographically capturing a person's physical handwritten ink signature for insertion into electronic documents or PDF forms","A numeric personal identification code entered by an authorized user to approve document workflows and advance signature requests within electronic contract management platforms"],answer:1,explanation:"Digital signatures (RSA, ECDSA) provide authentication (who signed it), integrity (the content wasn't changed), and non-repudiation (the signer cannot deny signing).",optionExplanations:["Electronic signatures are a broad legal concept encompassing typed names and clicks; digital signatures are specifically cryptographic mechanisms providing mathematical proof of identity and message integrity.","A digital signature hashes the message content, then encrypts the hash with the signer's private key — recipients decrypt with the public key and verify the hash matches the message.","Scanned handwritten signature images are bitmap graphics with no cryptographic properties or tamper evidence; digital signatures use asymmetric cryptography to provide mathematically verifiable authenticity.","PINs are authentication factors for access control and workflow approval; digital signatures use private keys to generate cryptographic proofs of identity and message content integrity."]},
  {id:516,domain:T,question:"What is a smishing attack?",options:["A threat actor social engineering technique combining in-person approaches near outdoor smoking areas with follow-up phishing emails targeting the same contacted individuals","Phishing conducted via SMS/text messages, attempting to lure victims into clicking malicious links or calling fraudulent phone numbers","A phishing variant that embeds emoji characters, smiley faces, and informal friendly language in messages to appear non-threatening and reduce victim suspicion of malicious intent","A low-frequency, extended-duration phishing campaign that sends a small number of targeted messages across weeks or months to avoid triggering spam filters and user suspicion"],answer:1,explanation:"Smishing exploits SMS's perceived trustworthiness — people are more likely to click text message links than email links, and mobile users often can't inspect URLs before clicking.",optionExplanations:["Smoking area social engineering is a pretexting technique; smishing is specifically the use of SMS text messages as the delivery channel for phishing attacks against mobile users.","Smishing sends text messages claiming to be banks, delivery services, or government agencies with urgent links — 'Your package is held, verify here' or 'Your account is suspended'.","Emoji and friendly tone are stylistic techniques some phishing uses; smishing is defined specifically by SMS delivery channel, not by the visual tone or formatting of the message.","Slow, persistent phishing campaigns describe a timing-based evasion strategy; smishing is specifically defined by the use of SMS text messages as the communication channel."]},
  {id:517,domain:A,question:"What is a cloud workload protection platform (CWPP)?",options:["A cloud financial operations platform that tracks, forecasts, and optimizes cloud infrastructure spending across multiple providers using budget alerts, tagging, and cost allocation","A security solution providing visibility and protection for workloads across public clouds, private clouds, and on-premises environments, including VMs, containers, and serverless","A cloud-native observability platform that collects and visualizes performance metrics, application logs, and distributed traces from cloud applications and microservices infrastructure","An infrastructure-as-code orchestration platform such as Terraform or Pulumi that enables consistent automated provisioning and deployment of workloads across multiple cloud providers"],answer:1,explanation:"CWPPs (Prisma Cloud, Defender for Cloud) apply runtime protection, vulnerability management, and behavioral monitoring to cloud workloads regardless of where they run.",optionExplanations:["Cloud cost management is FinOps; CWPPs focus on security protection of workloads including vulnerability scanning, runtime threat detection, and security policy enforcement for cloud-deployed assets.","A CWPP provides unified security across hybrid and multi-cloud environments — scanning workload images for vulnerabilities, detecting runtime threats, and enforcing security policies for VMs, containers, and functions.","Observability platforms collect operational performance data; CWPPs specifically provide security protection including active threat detection, vulnerability scanning, and policy enforcement for workloads.","Multi-cloud deployment orchestration platforms manage infrastructure provisioning; CWPPs provide security for already-deployed workloads, not the deployment mechanism itself."]},
  {id:518,domain:O,question:"What is the difference between a full backup and an incremental backup?",options:["Full backup jobs apply AES-256 encryption to all archived data at rest, while incremental backup jobs transmit data in plaintext to reduce processing overhead and speed","A full backup copies all data; an incremental backup copies only data changed since the last backup — balancing storage efficiency with recovery complexity","Incremental backups provide stronger security protection than full backups because their smaller size makes encryption, offsite transfer, and secure long-term storage more manageable","Full backup jobs are scheduled to run on a weekly basis while incremental backup jobs are executed monthly to spread storage costs and reduce backup window duration"],answer:1,explanation:"Full: simple recovery (restore one backup) but slow and storage-intensive. Incremental: fast and efficient but complex recovery (restore full + all incrementals in order).",optionExplanations:["Backup types differ in what data they capture, not in whether encryption is applied; both full and incremental backups should be encrypted regardless of the backup type.","Full backups copy everything (baseline), while incremental backups copy only changes since the last backup — reducing backup time and storage but requiring sequential restoration.","Both backup types require equivalent security controls regardless of size; incremental backups do not inherently offer greater security than full backups, only storage and time efficiency.","Backup scheduling frequency is an organizational policy decision; the distinction between full and incremental backups is what data they capture — all data versus changes since the last backup."]},
  {id:519,domain:T,question:"What is a man-in-the-middle attack using SSL stripping?",options:["Revoking or removing SSL/TLS certificates from web servers to force those servers to fall back to serving all web content over unencrypted HTTP connections","Downgrading an HTTPS connection to HTTP by intercepting the initial connection before the browser receives the HTTPS redirect, allowing plaintext interception","Uninstalling or disabling TLS client libraries and certificate trust stores from a victim's device to prevent the device from establishing any encrypted HTTPS connections","Decrypting and permanently removing encryption from files stored on a target device or server, converting protected ciphertext back into recoverable accessible plaintext format"],answer:1,explanation:"SSL stripping intercepts the user's initial HTTP request before the server can redirect to HTTPS, serving HTTP while maintaining HTTPS with the server — the user is unaware they're unprotected.",optionExplanations:["Revoking server certificates is certificate lifecycle management or an attack on server configuration; SSL stripping is a client-side network interception attack manipulating connection establishment.","SSL stripping works at the connection initiation phase — the attacker intercepts HTTP traffic and maintains HTTP with the client while upgrading to HTTPS with the server, seeing all plaintext.","Removing TLS capabilities from a device is an endpoint attack requiring access; SSL stripping is a network-level attack intercepting connections in transit without requiring access to the device.","File decryption is a storage-layer operation distinct from transport security; SSL stripping specifically targets the connection negotiation between browser and server to downgrade HTTPS to HTTP."]},
  {id:520,domain:G,question:"What is the OWASP Top 10?",options:["An annual analyst report published by firms such as Gartner or Forrester ranking the top ten cybersecurity product vendors by market revenue, capability ratings, and customer satisfaction","A regularly updated list of the most critical web application security risks, serving as a standard awareness document for developers and security teams","A law enforcement or cybersecurity organization-published list ranking the most dangerous active threat actor groups and individual hackers by assessed capability and attack impact","A compliance framework published by a regulatory authority that specifies ten mandatory technical security controls all organizations in a regulated sector must implement and audit annually"],answer:1,explanation:"OWASP Top 10 (injection, broken auth, sensitive data exposure, XSS, etc.) is the most referenced web security standard — many compliance frameworks require addressing it.",optionExplanations:["Security vendor rankings are commercial analyst reports; the OWASP Top 10 is a technical awareness document identifying the most prevalent and impactful web application vulnerability categories.","The OWASP (Open Web Application Security Project) Top 10 identifies and describes the most prevalent and impactful web application security risks — with descriptions, examples, and prevention guidance.","Threat actor rankings do not exist as a recognized security standard; the OWASP Top 10 identifies web application vulnerability risk categories, not threat actors or individuals.","The OWASP Top 10 is guidance and awareness material, not a regulatory mandate; while referenced in compliance, it is a risk awareness framework, not a required control standard."]},
  {id:521,domain:O,question:"What is a red team engagement?",options:["A competitive team exercise format where multiple groups compete against each other to complete security capture-the-flag challenges using equipment and systems designated in red","An authorized, adversarial simulation where a team acts as a realistic threat actor to test the organization's defenses, detection, and response capabilities holistically","A monthly organization-wide security drill placing all systems under elevated alert status to practice emergency notification escalation procedures and test incident communication channels","A dedicated team of security analysts and forensic investigators whose primary function is detecting, analyzing, containing, and remediating active cybersecurity incidents in real time"],answer:1,explanation:"Red teams go beyond point-in-time penetration tests — they simulate entire attack campaigns (initial access, lateral movement, data exfiltration) over weeks or months.",optionExplanations:["CTF competitions use 'red' descriptively; red team engagements are authorized adversarial simulations against a specific organization's real defenses, detection capabilities, and response teams.","A red team engagement simulates a real adversary using the same TTPs, testing not just technical controls but detection capability, response time, and response effectiveness.","Red alert security drills test notification procedures; red team engagements simulate realistic adversaries using actual attack techniques to test detection, response effectiveness, and security controls holistically.","Incident detection and response teams are the blue team; red teams conduct authorized offensive simulations acting as realistic adversaries to test the effectiveness of defensive capabilities."]},
  {id:522,domain:T,question:"What is a keylogger?",options:["A dedicated hardware security module or software-based credential vault that generates, stores, rotates, and controls access to cryptographic encryption keys and digital certificates","Software or hardware that records keystrokes to capture passwords, credit card numbers, and other sensitive data typed by the user","An audit logging system that records all physical access key issuances, returns, and badge swipe events for facility entry management and physical security accountability","A software application or browser extension that automatically generates, stores, and fills in strong random passwords for websites and online accounts on behalf of the user"],answer:1,explanation:"Hardware keyloggers plug between keyboard and PC; software keyloggers run as processes — both capture everything typed including passwords and sensitive data.",optionExplanations:["Key management devices like HSMs store and manage cryptographic keys; keyloggers capture keyboard input to steal user-typed credentials, passwords, and sensitive data for attacker use.","Keyloggers intercept keyboard input at the hardware or OS level, recording all keystrokes and often sending them to remote attackers — capturing credentials, PINs, and sensitive communications.","Physical key issuance logs are facility security records; keyloggers are malicious tools that record keyboard input at the OS or hardware level to capture user-typed credentials.","Password managers generate and store credentials for convenience; keyloggers are surveillance tools that secretly record all keystrokes to capture passwords that users type into systems."]},
  {id:523,domain:A,question:"What is cloud-native security?",options:["Security services, built-in controls, and native features included within cloud service providers' platforms such as IAM, default encryption at rest, and DDoS protection capabilities","Security approaches and tools designed specifically for cloud environments — using cloud APIs, automation, and ephemeral infrastructure rather than adapting traditional on-premises tools","Application security practices applied specifically to programs written in languages that are natively compiled and executed within cloud platform serverless or container runtime environments","Security controls and hardening practices applied to applications specifically developed using languages such as Go or Rust that are commonly adopted in cloud microservices development"],answer:1,explanation:"Cloud-native security uses IaC scanning, CSPM, CWPP, and cloud API integration — traditional perimeter tools can't inspect API calls and serverless function invocations.",optionExplanations:["CSP-provided native security is one component of a cloud security strategy; cloud-native security is a broader architectural approach purpose-built for cloud environments using automation and APIs.","Cloud-native security embraces immutable infrastructure, automated security testing in CI/CD, cloud-specific controls, and API-based integration with cloud services — going beyond lifting-and-shifting traditional tools.","Language-specific application security is a subset of secure coding; cloud-native security addresses the full security architecture and tooling approach for cloud environments at infrastructure scale.","Programming language security practices are a development concern; cloud-native security encompasses the entire security architecture, automation, and tooling strategy optimized for cloud-scale environments."]},
  {id:524,domain:P,question:"What is the accountability principle in data privacy?",options:["Holding individual employees, contractors, or administrators personally liable and subject to disciplinary action for data breaches caused by their negligent or intentional actions","The obligation of data controllers to be responsible for and demonstrate compliance with data protection principles","The financial penalties, administrative fines, and regulatory sanctions that supervisory authorities impose on organizations for violations of data protection regulations such as GDPR","The contractual and regulatory obligation of data processors to follow controller instructions, implement appropriate security safeguards, and notify controllers of incidents within required timeframes"],answer:1,explanation:"GDPR accountability (Article 5(2)) requires controllers to not only comply but to demonstrate compliance — through DPIAs, records of processing, policies, and DPO appointment.",optionExplanations:["Individual liability for breaches may be part of enforcement; the accountability principle places responsibility on the data controller organization to demonstrate compliance with all data protection principles.","Accountability requires organizations to document their data processing activities, implement appropriate safeguards, and be able to demonstrate to regulators that they comply with data protection law.","Financial penalties are one enforcement mechanism for non-compliance; the accountability principle is about organizational responsibility for implementing safeguards and being able to demonstrate compliance.","Processor obligations to controllers are governed by Article 28 processor agreements; the accountability principle broadly places responsibility on controllers for the entire data processing operation."]},
  {id:525,domain:G,question:"What is entropy in cryptography?",options:["The degree of structural disorganization or bit-pattern unpredictability within cryptographic key material, measured in bits as an indicator of overall key randomness and strength","The measure of unpredictability or randomness in a system — high entropy sources are essential for generating strong cryptographic keys and nonces","The amount of electrical power consumed by hardware and software components when executing cryptographic algorithms such as AES, RSA, or elliptic curve operations under load","The computational difficulty and algorithmic work factor of an encryption scheme as measured by the number of mathematical operations required to complete encryption or decryption"],answer:1,explanation:"Low entropy (predictable seeds) leads to weak keys — the Debian OpenSSL bug (2008) that limited random number generation to 32,768 possible values made all generated keys predictable.",optionExplanations:["Key unpredictability is related to entropy but disorder alone is not the cryptographic definition; entropy quantifies how unpredictable a random source is, which determines key strength.","Cryptographic entropy quantifies how unpredictable a random number generator is — high entropy (true randomness) produces keys that cannot be predicted; low entropy makes keys predictable and attackable.","Energy consumption is a physical characteristic measured in watts; cryptographic entropy is a mathematical measure of randomness quality in bits, not an energy or power measurement.","Algorithmic complexity measures computational effort; entropy measures the quality and unpredictability of randomness used to generate keys, not the difficulty of the encryption algorithm itself."]},
  {id:526,domain:O,question:"What is security hardening?",options:["Manufacturing physical security hardware components such as server enclosures, cable locks, and access barriers from more durable materials to resist physical tampering and destruction","The process of securing a system by reducing its attack surface — disabling unnecessary services, closing unused ports, removing default accounts, and applying secure configurations","Upgrading all systems to implement stronger encryption algorithms by replacing deprecated ciphers with AES-256 for data at rest and TLS 1.3 for all data in transit","Tightening existing firewall rule sets by removing overly permissive allow rules and implementing more restrictive policies to block additional categories of unauthorized network traffic"],answer:1,explanation:"Hardening follows CIS Benchmarks or DISA STIGs — disabling Telnet, removing default passwords, patching, disabling USB ports, and configuring required services securely.",optionExplanations:["Hardening physical security hardware is physical security equipment engineering; security hardening addresses software attack surface reduction through configuration changes, not physical material durability.","Security hardening systematically removes unnecessary functionality and applies security configurations — each unnecessary service or open port is a potential attack vector eliminated through hardening.","Encryption strengthening is one security hardening activity among many; hardening comprehensively reduces the attack surface including unnecessary services, open ports, default credentials, and insecure configurations.","Firewall rule tightening is perimeter security hardening; system hardening addresses the systems themselves by removing unnecessary services, closing ports, and applying secure baseline configurations."]},
  {id:527,domain:T,question:"What is living-off-the-land (LotL) binaries (LOLBins)?",options:["The physical and strategic planning practice of siting server farms and data center campus facilities on agricultural or undeveloped rural land to reduce real estate costs","Legitimate system executables (certutil, mshta, regsvr32, rundll32) abused by attackers to download payloads, execute code, or bypass application controls","Compiled executable binary files that reside on and execute from servers located in terrestrial on-premises data centers rather than in public cloud or virtual infrastructure","Compiled executable programs deployed in smart farming equipment, precision agriculture sensor systems, and rural supply chain management platforms for agricultural operations"],answer:1,explanation:"LOLBins are trusted Windows/Linux binaries signed by Microsoft or the OS vendor — security tools often whitelist them, making them ideal for bypass.",optionExplanations:["Data center site selection on rural land is facility planning; LOLBins is a Windows and Linux security concept describing legitimate OS executables abused by attackers for malicious purposes.","LOLBins (Living Off The Land Binaries) include certutil.exe (downloads files), regsvr32 (executes DLLs), mshta (executes HTML applications) — all legitimate but frequently abused for malicious purposes.","On-premises server binaries are a deployment model description; LOLBins specifically refers to existing OS-native executables that attackers repurpose to execute malicious actions and evade detection.","Agricultural system executables are a completely different context; LOLBins is a cybersecurity term specifically describing OS-built-in executables repurposed by attackers to evade application controls."]},
  {id:528,domain:A,question:"What is application segmentation?",options:["Structuring application source code into independent functional modules or microservices to improve maintainability, reusability, and separation of software development responsibilities","Separating application tiers (web, application, database) into distinct network zones with access controls between them","Deploying application workloads across multiple geographic cloud regions to improve availability, reduce user latency, and satisfy data residency regulatory requirements for global operations","Organizing application end users into distinct groups based on job role or permission level, granting each group different feature visibility and data access permissions within the application"],answer:1,explanation:"Three-tier segmentation (DMZ for web → App tier behind firewall → DB tier on isolated network) ensures database servers are never directly reachable from the internet.",optionExplanations:["Code modularization is software architecture design; application segmentation is network security architecture that isolates application tiers into distinct network zones with access controls between them.","Application segmentation separates the presentation, logic, and data tiers into distinct security zones — even if the web tier is compromised, attackers can't directly access the database tier.","Geographic workload distribution is cloud availability architecture; application segmentation is network-level security isolation between application tiers to limit lateral movement after a compromise.","User group access control is RBAC applied within applications; application segmentation is network-level isolation of presentation, logic, and data tiers into separate security zones."]},
  {id:529,domain:P,question:"What is the right to access under GDPR?",options:["The right for any member of the public to freely access and inspect all data, records, and information held by any commercial, governmental, or nonprofit organization","An individual's right to request confirmation of whether their personal data is processed, and to receive a copy of that data and information about how it is used","The right of a data subject to submit a correction request requiring a data controller to update or amend inaccurate, incomplete, or outdated personal data held about them","The right of a data subject to request that an organization temporarily pause all non-essential processing of their personal data while accuracy or lawfulness is disputed"],answer:1,explanation:"GDPR Article 15 (Subject Access Request) gives individuals the right to know what data organizations hold about them — organizations must respond within one month.",optionExplanations:["Unrestricted access to any organization's data would constitute unauthorized access; the right of access applies only to an individual's own personal data held by an organization.","The right of access enables individuals to submit Subject Access Requests (SARs), receive confirmation of processing, a copy of their data, and information about purposes, retention, and sharing.","The right to have inaccurate data corrected is the right to rectification under GDPR Article 16; the right of access is specifically about receiving a copy of one's own data.","Pausing processing while accuracy is disputed is the right to restriction of processing under GDPR Article 18; the right of access is about viewing and obtaining copies of personal data."]},
  {id:530,domain:G,question:"What is a HMAC (Hash-Based Message Authentication Code)?",options:["A computationally intensive password-specific hashing algorithm such as bcrypt, scrypt, or Argon2 designed to resist brute-force and GPU-accelerated password cracking attacks","A MAC that uses a cryptographic hash function combined with a secret key to verify both data integrity and message authenticity","A network access control device or policy engine that manages and enforces MAC address filtering policies on network switches and wireless access points to control device connectivity","A public key infrastructure mechanism using X.509 digital certificates and asymmetric encryption to authenticate the identity of message senders in secure email or API systems"],answer:1,explanation:"HMACs (HMAC-SHA256) add a secret key to hashing — without the key, an attacker cannot create a valid HMAC even if they know the hash algorithm.",optionExplanations:["Password hashing algorithms like bcrypt protect stored passwords; HMAC is a message authentication code that combines a hash function with a shared secret key to verify message authenticity.","HMAC combines a hash function (SHA-256, SHA-3) with a shared secret key to produce an authentication code — verifying the message came from someone with the key and was not tampered with.","MAC address filtering is a network access control mechanism; HMAC is a cryptographic algorithm using a hash function combined with a secret key to produce message authentication codes.","Certificate-based authentication uses asymmetric PKI; HMAC uses a shared symmetric secret key combined with a hash function, not certificates, to verify message authenticity and integrity."]},
  {id:531,domain:T,question:"What is a cryptojacking attack?",options:["Gaining unauthorized access to cryptocurrency trading platforms and exchanges by exploiting web application vulnerabilities or API weaknesses to manipulate trades or steal funds","Unauthorized use of a victim's computing resources to mine cryptocurrency by deploying mining software through malware or malicious scripts","Stealing private keys, seed phrases, or wallet files from digital currency wallet software or hardware devices to transfer victims' cryptocurrency to attacker-controlled wallet addresses","Exploiting coding errors or logic flaws in blockchain smart contracts deployed on networks like Ethereum to drain funds from decentralized finance protocol liquidity pools"],answer:1,explanation:"Cryptojacking degrades victim system performance while generating cryptocurrency profit for attackers — delivered via malicious websites (browser mining) or malware.",optionExplanations:["Cryptocurrency exchange attacks target financial platforms; cryptojacking specifically hijacks victims' CPU and GPU resources to mine new cryptocurrency for attackers without the victim's knowledge.","Cryptojacking secretly installs mining software or runs JavaScript miners in browsers, consuming CPU/GPU resources to mine cryptocurrency for attackers while victims experience degraded performance.","Cryptocurrency wallet theft steals existing holdings from victims; cryptojacking mines new cryptocurrency using victims' computational resources rather than stealing directly from their wallets.","Smart contract exploitation is blockchain application security; cryptojacking hijacks computing resources for cryptocurrency mining operations rather than exploiting blockchain contract vulnerabilities."]},
  {id:532,domain:A,question:"What is a next-generation firewall (NGFW)?",options:["A firewall appliance built on specialized high-performance dedicated hardware with custom ASICs and multi-core processors optimized for high-throughput stateful packet processing","A firewall that combines traditional packet filtering with deep packet inspection, application awareness, user identity tracking, and intrusion prevention capabilities","A virtualized or containerized firewall solution architecturally designed and optimized specifically for deployment in public cloud environments using cloud-native APIs and auto-scaling","A firewall product that applies machine learning models and behavioral analytics to evaluate each connection attempt and make autonomous real-time allow or block decisions"],answer:1,explanation:"NGFWs (Palo Alto, Fortinet) identify applications regardless of port — 'allow Facebook but block Facebook Games' — and correlate traffic with user identities from directory services.",optionExplanations:["Hardware specifications do not define NGFW classification; NGFW capabilities are defined by deep packet inspection depth, application identification, user identity awareness, and integrated IPS functionality.","NGFWs go beyond IP/port filtering — they inspect application layer protocols, identify applications, enforce user-based policies, decrypt and inspect SSL traffic, and include integrated IPS.","Cloud-native firewalls are a deployment model and form factor; NGFW refers to inspection depth and application-layer capabilities regardless of whether deployment is on-premises or cloud-based.","AI-based decision making may be a feature in some advanced products; NGFW is defined by application-layer deep packet inspection, user identity tracking, and integrated intrusion prevention."]},
  {id:533,domain:O,question:"What is continuous integration/continuous deployment (CI/CD) security?",options:["Ensuring that software development and deployment activities occur on a rapid, frequent, and uninterrupted schedule with no gaps or delays in the automation and release workflow","Securing the automated software build and deployment pipeline from code commit through production deployment to prevent supply chain attacks and code tampering","Embedding security professionals directly into agile development sprint teams so security reviews, threat modeling, and code analysis occur continuously throughout the development lifecycle","An automated process for continuously packaging, testing, and deploying security patches and vulnerability fixes to all managed organizational systems as soon as they become available"],answer:1,explanation:"CI/CD pipeline attacks (like SolarWinds) compromise build systems to inject malicious code — security includes signed commits, SAST scanning, secret detection, and artifact signing.",optionExplanations:["Development and deployment continuity is a DevOps productivity goal; CI/CD security specifically addresses protecting the pipeline itself from supply chain attacks and malicious code injection.","Securing CI/CD pipelines involves protecting build servers, signing code commits, running SAST/SCA in pipelines, scanning container images, and signing deployment artifacts.","Integrating security into development teams is DevSecOps culture; CI/CD pipeline security is the technical discipline of protecting automated build, test, and deployment infrastructure from compromise.","Automated patch deployment is one CI/CD pipeline use case; CI/CD security addresses protecting the entire pipeline from source code through production deployment against supply chain attacks."]},
  {id:534,domain:T,question:"What is a rootkit's primary defense evasion technique?",options:["Applying encryption and code obfuscation techniques to the malware binary payload to prevent antivirus signature databases from matching it against known malware samples","Subverting operating system functions to conceal its own presence and the presence of other malware from security tools and administrators","Using stolen or fraudulently obtained code signing certificates to digitally sign malicious executables so they appear as trusted legitimate software to endpoint security controls","Renaming malicious process executables and service names to match exactly those of legitimate Windows or Linux system processes to blend into normal process listings"],answer:1,explanation:"Kernel-level rootkits (ring 0) hook system calls, modifying what the OS reports to security tools — making files, processes, and network connections invisible.",optionExplanations:["Code encryption for signature evasion is used by many malware types; rootkit evasion specifically subverts OS-level visibility so the rootkit and other malware are hidden from security tools.","Rootkits intercept OS API calls (e.g., listing files, listing processes) and filter out their own entries — security tools see a 'clean' system because the rootkit controls what the OS reports.","Code signing certificate abuse is a separate evasion technique; rootkits specifically modify operating system functions to hide their own presence from processes listing files or running programs.","Process name masquerading is a visibility evasion technique; rootkits go deeper by intercepting OS API calls to filter out their own entries from what the operating system reports."]},
  {id:535,domain:G,question:"What is end-to-end encryption (E2EE)?",options:["Encrypting all network traffic between a client device and a destination server using TLS to protect data from eavesdropping by third parties on the network path","Encryption where only the communicating endpoints can decrypt messages — the service provider handling the transmission cannot decrypt the content","A comprehensive data protection strategy that applies encryption both to data stored on disk, in databases, and in backups and to data transmitted over all network connections","An encryption method that protects all data stored on an entire storage device by encrypting every sector, including the operating system, using a pre-boot authentication key"],answer:1,explanation:"E2EE (Signal, WhatsApp, ProtonMail) means the service provider cannot read your messages even if legally compelled — keys exist only on endpoint devices.",optionExplanations:["TLS transport encryption protects data in transit but allows the server to decrypt and read the content; E2EE prevents even the service provider's servers from decrypting messages.","E2EE means encryption keys only exist on the sender and receiver — intermediary servers transmit ciphertext they cannot decrypt, providing privacy even if the service provider is compromised or compelled.","Encrypting both storage and transit is a general data protection approach; E2EE specifically ensures no intermediary between communicating endpoints can decrypt the content during transmission.","Full disk encryption protects data at rest on a storage device; E2EE protects data in transit between communicating endpoints so no intermediate server or provider can access plaintext."]},
  {id:536,domain:P,question:"What is a data breach notification requirement?",options:["Proactively informing existing customers about newly developed data products, services, or features through planned marketing and communications channels","Legal obligation to inform affected individuals and regulatory authorities when personal data has been compromised through unauthorized access, within specific timeframes","An internal IT incident report documenting technical details of a security event for the organization's own records and remediation tracking","A mandatory news media announcement that organizations must issue to inform the general public whenever a significant data breach has occurred"],answer:1,explanation:"GDPR requires notification to supervisory authority within 72 hours and to affected individuals 'without undue delay' — many US states have similar laws with varying timeframes.",optionExplanations:["Customer notifications about new products are marketing activities; breach notifications are legally mandated obligations triggered by unauthorized access events, not product launches.","Breach notification laws require organizations to inform individuals whose data was exposed (so they can protect themselves) and regulators (for oversight) within defined timeframes.","Internal incident reports document events for internal use and remediation; breach notification requirements mandate external communications to individuals and regulators within defined legal timeframes.","Media notifications may occur voluntarily or be required for very large breaches; legal notification requirements specifically mandate informing affected individuals and regulators, not necessarily the general media."]},
  {id:537,domain:A,question:"What is a secure enclave?",options:["A physically secured data center room with biometric access controls, reinforced walls, CCTV monitoring, and environmental sensors to protect server infrastructure","A hardware-isolated execution environment within a processor that provides confidential computing, protecting code and data from the host OS and other applications","A logically separated network segment with strict firewall rules and access controls that isolates sensitive systems from the general corporate network","A tamper-resistant hardware security module (HSM) container that stores cryptographic keys, performs key operations, and provides a secure boundary for key material"],answer:1,explanation:"Intel SGX, AMD SEV, and ARM TrustZone create isolated memory regions — even the hypervisor or OS cannot inspect enclave memory, enabling confidential cloud computing.",optionExplanations:["Physically secured data center rooms are facility security controls; secure enclaves are hardware isolation features built into processors, not physical rooms.","Secure enclaves (Intel SGX, Apple Secure Enclave) create protected memory regions where code and data are encrypted and isolated from the rest of the system — including privileged software.","Protected network segments are network segmentation security controls; secure enclaves are processor-level hardware isolation features, not network architecture components.","HSMs are dedicated cryptographic hardware with secure key storage; secure enclaves are processor features creating protected memory regions for general confidential computation."]},
  {id:538,domain:O,question:"What is the purpose of a configuration management database (CMDB)?",options:["Storing and versioning database server configuration files such as settings, connection strings, and parameters in a shared repository for administrator access","A repository that maintains records of all IT assets (configuration items) and their relationships, supporting change management and incident response","A centralized database that stores security tool configurations, firewall rule sets, and endpoint policy settings for consistent enforcement across systems","A management console designed exclusively for database administrators to monitor query performance, manage schema changes, and configure database security settings"],answer:1,explanation:"CMDBs enable impact analysis (what does changing this server affect?), support incident investigation (what changed recently?), and maintain the asset inventory security teams need.",optionExplanations:["Database configuration file storage is a DevOps or infrastructure task; CMDBs track all IT assets and their interdependencies across the entire organization.","A CMDB is the authoritative record of IT assets (servers, applications, network devices) and how they relate — enabling change impact analysis, incident troubleshooting, and security inventory.","Security configuration databases store policy settings; CMDBs maintain records of all IT assets and their relationships to support change management and incident response.","DBA management tools handle database-specific tasks; CMDBs serve all IT operations teams and track the entire IT asset landscape, not just database systems."]},
  {id:539,domain:T,question:"What is a multi-vector attack?",options:["An attack that routes malicious traffic through multiple IP addresses or proxy servers to evade IP-based blocking and make attribution more difficult","An attack combining multiple attack techniques and channels simultaneously to overwhelm defenses, increase chances of success, and complicate detection and response","A widespread attack campaign that simultaneously targets many different organizations or individuals, maximizing the attacker's reach and overall financial or strategic impact","A worm or virus that propagates laterally across multiple network segments by exploiting routing trust relationships between otherwise segmented organizational networks"],answer:1,explanation:"Modern attacks rarely use a single technique — phishing delivers ransomware that exploits a vulnerability during installation while C2 uses legitimate cloud services to evade detection.",optionExplanations:["Multiple IP address usage is an evasion technique; multi-vector attacks combine multiple distinct attack techniques and delivery channels, not just varying source addresses.","Multi-vector attacks use phishing, exploit kits, USB drops, and living-off-the-land simultaneously — making it harder to block all entry points and creating response complexity.","Broad victim targeting is campaign scope; multi-vector attacks combine different techniques against potentially the same target, not simply the number of victims targeted.","Spreading across network segments is worm or lateral movement behavior; multi-vector attacks use multiple different techniques and channels rather than a single spreading mechanism."]},
  {id:540,domain:G,question:"What is post-quantum cryptography (PQC)?",options:["Cryptographic systems organizations plan to deploy once practical quantum computers become widely available and current encryption methods are deprecated by standards bodies","Classical mathematical algorithms designed to be resistant to attacks by quantum computers, addressing the threat that quantum computing poses to current encryption","Cryptography that leverages quantum mechanical phenomena such as superposition and entanglement to perform encryption computations on today's classical hardware systems","Next-generation communications systems that use quantum key distribution channels and quantum entanglement to transmit encrypted messages with unconditional security guarantees"],answer:1,explanation:"NIST PQC standards (CRYSTALS-Kyber, CRYSTALS-Dilithium, SPHINCS+) selected in 2024 replace RSA/ECC which quantum computers can break using Shor's algorithm.",optionExplanations:["PQC is deployed now to protect data collected today from future quantum decryption; it is not a future deployment plan but a present-day cryptographic practice.","PQC algorithms use mathematical problems (lattice-based, hash-based, code-based) that are hard for both classical and quantum computers — replacing vulnerable RSA and ECC.","PQC runs on classical computers using mathematical problems resistant to quantum attacks, not quantum physics; quantum mechanical cryptography describes QKD, not PQC algorithms.","Quantum key distribution (QKD) uses quantum physics for secure communications; PQC is classical mathematical algorithms designed to resist quantum computer attacks, not quantum-based communications."]},
  {id:541,domain:T,question:"What is a drive-by cryptomining attack?",options:["Mining cryptocurrency by physically transporting computing hardware to geographic locations that offer cheaper electricity rates, reducing operational costs through strategic facility placement","JavaScript code embedded in malicious or compromised websites that mines cryptocurrency using visitors' browser CPU resources without their knowledge","Installing persistent cryptocurrency mining software on a victim's device by exploiting browser vulnerabilities when the target visits a maliciously crafted website","An attack specifically targeting mobile devices that installs cryptomining applications through malicious app stores or drive-by downloads to drain battery and processing power"],answer:1,explanation:"Browser-based miners (Coinhive was infamous) run without installation — any browser visiting the page mines cryptocurrency, often going undetected except for high CPU usage.",optionExplanations:["Physical relocation for cheaper electricity is a legitimate mining cost optimization; drive-by cryptomining exploits website visitors' browsers without any installation or physical hardware setup.","Drive-by cryptomining embeds JavaScript mining code in web pages — visitors' browsers automatically execute it, consuming CPU to mine cryptocurrency for the attacker without downloading any files.","Installation-based mining requires exploiting a vulnerability to write malware to disk; drive-by cryptomining executes JavaScript directly in the browser without any software installation.","Mobile cryptomining attacks specifically target smartphones and tablets through app-based infection; drive-by cryptomining refers to browser-based delivery via websites, affecting any device with a browser."]},
  {id:542,domain:A,question:"What is software composition analysis (SCA)?",options:["Analyzing the organizational structure, skill sets, and staffing levels of software development teams to optimize resource allocation and project delivery timelines","Automated analysis of software projects to identify open source components, their versions, known vulnerabilities, and license obligations","Manually decomposing software architecture into individual subsystems and modules for security architects to review design patterns, data flows, and trust boundaries","A procurement analysis comparing the licensing costs and total cost of ownership of proprietary software components versus commercially available third-party alternatives"],answer:1,explanation:"SCA tools (Snyk, Black Duck, Dependabot) identify vulnerable open source libraries before attackers exploit them — Log4Shell affected millions of apps using Log4j.",optionExplanations:["Team composition analysis is workforce management; SCA analyzes the software codebase's open source dependency components, their versions, and associated security vulnerabilities.","SCA inventories all open source libraries in a codebase (the software bill of materials/SBOM), checks them against CVE databases, and flags vulnerable or unlicensed components.","Architecture decomposition for review is part of threat modeling; SCA specifically identifies third-party open source libraries in a codebase and checks them for known vulnerabilities.","Component pricing analysis is a procurement and financial activity; SCA is a security practice identifying vulnerable and improperly licensed open source components."]},
  {id:543,domain:O,question:"What is a penetration test report?",options:["A performance assessment report documenting network throughput, latency, packet loss, and bandwidth utilization measurements taken during scheduled load and stress testing activities","A detailed document from a penetration test engagement covering scope, methodology, discovered vulnerabilities, exploitation evidence, risk ratings, and remediation recommendations","A financial accounting document submitted by a contracted penetration tester to request reimbursement for travel, tools, and professional expenses incurred during the engagement","A formal certificate of completion issued to an organization confirming that penetration testing services were performed within a specified scope and timeframe"],answer:1,explanation:"Pentest reports provide technical findings for IT teams (reproduction steps, payloads) and executive summaries for leadership (risk ratings, business impact, prioritized recommendations).",optionExplanations:["Network speed test reports measure performance capacity; pentest reports document security vulnerabilities discovered through authorized attack simulation and their remediation paths.","A comprehensive pentest report documents scope, methodology, attack narratives, proof-of-concept evidence, vulnerability details, CVSS scores, and actionable remediation guidance.","Expense reports are financial documents for contractor billing; pentest reports are the primary technical deliverable documenting discovered vulnerabilities and recommended security improvements.","Completion certificates confirm the test took place; the pentest report is the substantive technical deliverable documenting what vulnerabilities were found and how to fix them."]},
  {id:544,domain:P,question:"What is data classification?",options:["Organizing and sorting data records by their creation timestamp, modification date, or access date to support retention schedules and lifecycle management policies","The process of categorizing data based on its sensitivity and business value to determine appropriate handling, storage, and protection requirements","Categorizing business transactions and financial records according to tax code requirements to support accurate reporting, deduction claims, and regulatory tax compliance","Designing relational database schemas by organizing data fields into normalized tables with appropriate primary keys, foreign key relationships, and indexing strategies"],answer:1,explanation:"Data classification (Public, Internal, Confidential, Restricted/Top Secret) drives security controls — unclassified data gets minimal protection; restricted data gets the strongest.",optionExplanations:["Date-based organization is records management and data lifecycle administration; data classification categorizes by sensitivity level to determine the required security controls and handling procedures.","Data classification assigns sensitivity labels that determine encryption requirements, access controls, handling procedures, retention periods, and disposal methods appropriate for each data category.","Tax classification is a financial reporting requirement; data classification is a security governance process that assigns sensitivity labels to determine appropriate data protection measures.","Database schema design is data architecture and database engineering; classification is a security governance process assigning sensitivity levels that determine encryption, access controls, and retention requirements."]},
  {id:545,domain:G,question:"What is block cipher mode of operation?",options:["The configuration setting that determines whether a web server processes symmetric encryption operations using hardware-accelerated SSL offload cards or software-based cipher implementations","Defines how a block cipher algorithm processes data larger than a single block — different modes have different properties for confidentiality, integrity, and performance","The processor privilege level or ring mode that the CPU operates in when executing cryptographic library functions, determining memory access and hardware instruction permissions","A hardware appliance configuration setting that determines which cipher suites, key lengths, and protocol versions the encryption device offers during TLS negotiation with clients"],answer:1,explanation:"ECB (never use — reveals patterns), CBC (sequential, needs IV), CTR (parallel, stream-like), GCM (provides both encryption and integrity) each have different security properties.",optionExplanations:["Server cipher configuration relates to SSL/TLS implementation choices; cipher modes define how block cipher algorithms handle data spanning multiple blocks.","Modes like CBC, GCM, and CTR solve the problem of encrypting data larger than one block (16 bytes for AES) — each mode trades off security properties, performance, and parallelizability differently.","CPU privilege rings are processor architecture concepts; cipher operating modes are cryptographic specifications defining how block ciphers chain multiple blocks together.","Appliance configuration modes are management and policy settings on hardware devices; cipher modes are cryptographic algorithm specifications governing how block encryption algorithms process multi-block messages."]},
  {id:546,domain:T,question:"What is an insider threat?",options:["Security threats originating from employees at competitor organizations, neighboring companies, or business partners who attempt unauthorized access to your systems from outside","Security threats originating from people within the organization — current/former employees, contractors, or business partners who misuse authorized access","A threat arising from any malicious actor who has gained network access, whether through VPN compromise, rogue wireless access, or perimeter firewall bypass","A phishing or pretexting attack where an external threat actor specifically targets internal employees through email, phone, or in-person deception to steal credentials or data"],answer:1,explanation:"Insider threats are particularly dangerous because they bypass perimeter controls — they have legitimate access and knowledge of sensitive systems and data locations.",optionExplanations:["Threats from competitor or adjacent organizations are external threats or third-party risks; insider threats specifically involve people who have authorized access to the organization's own systems.","Insider threats include malicious insiders (deliberate data theft, sabotage), negligent insiders (accidental exposure, falling for phishing), and compromised insiders (account takeover).","Network perimeter threats may involve external attackers who penetrated the perimeter; insider threats specifically involve authorized individuals with legitimate access acting against organizational interests.","Social engineering targeting employees is an external attack using insiders as a conduit through deception; true insider threats involve those with existing authorized access who knowingly act against the organization."]},
  {id:547,domain:A,question:"What is a content delivery network (CDN) and its security benefits?",options:["A private internal network that distributes corporate documents, software updates, and multimedia content to employees across different office locations through local file servers","A distributed network of servers that delivers content to users from geographically close locations, also providing DDoS mitigation and web application security","A dedicated network infrastructure specifically designed to transport encrypted media streams and DRM-protected content to authorized subscribers using secure delivery protocols","A web content management platform that allows authors to create, edit, organize, and publish website content through a browser-based administrative interface"],answer:1,explanation:"CDNs (Cloudflare, Akamai, Fastly) absorb DDoS attacks through distributed capacity, hide origin server IPs, and can enforce WAF and bot mitigation policies globally.",optionExplanations:["Internal corporate distribution networks serve employees within the organization; CDNs serve external public internet users from geographically distributed edge servers.","CDNs distribute content globally to improve performance but also provide security: hiding origin server IP addresses, absorbing DDoS traffic, applying WAF policies at edge, and filtering malicious bots.","Encrypted content delivery networks are a specialized use case; CDNs provide general-purpose content acceleration plus security features like DDoS mitigation and WAF capabilities.","Content management systems (CMS) handle content creation and publishing workflows; CDNs distribute already-published content globally to improve delivery speed and provide security protection."]},
  {id:548,domain:O,question:"What is a business continuity plan (BCP)?",options:["A strategic business expansion plan that outlines market entry strategies, growth targets, resource requirements, and timelines for entering new geographic markets or product lines","A comprehensive plan ensuring critical business functions can continue during and after a disruptive event, including procedures for people, processes, and technology","A strategic contingency plan outlining alternative business strategies and pivots that management can activate when the primary business model or market strategy fails","A fire safety and emergency evacuation procedure defining assembly points, evacuation routes, and personnel accountability processes for immediate life-safety events in office buildings"],answer:1,explanation:"BCPs address all aspects of business survival during disruptions — who does what, where teams work if offices are inaccessible, how customers are served, and how systems are restored.",optionExplanations:["Business expansion plans address strategic growth objectives; BCPs address operational resilience and continuity during disruptions that threaten existing business operations.","A BCP documents how essential business functions continue when normal operations are disrupted — alternative work locations, manual procedures, communication plans, and recovery priorities.","Failed strategy contingency plans are strategic management tools; BCPs address operational disruptions to business processes, facilities, and technology infrastructure during disasters.","Emergency evacuation procedures address immediate life-safety events and are one component of broader emergency management; BCPs focus on maintaining business operations during extended disruptions."]},
  {id:549,domain:T,question:"What is a Slowloris attack?",options:["An attack that deliberately routes traffic through slow dial-up or satellite connections to evade detection systems that flag unusually high-speed network traffic patterns","A low-bandwidth application-layer DDoS attack that holds server connections open by sending partial HTTP requests, exhausting available connection pools","A credential brute-force attack that introduces artificial delays between password attempts to avoid triggering account lockout thresholds and evade rate-limiting security controls","A network reconnaissance technique that uses very slow port scanning with long intervals between probes to evade intrusion detection systems that detect rapid scanning"],answer:1,explanation:"Slowloris keeps many HTTP connections open with partial headers, never completing them — the server holds connections indefinitely, exhausting its connection limit and denying service to legitimate users.",optionExplanations:["Slow connections as evasion are a general concept; Slowloris specifically exploits the behavior of HTTP servers that maintain open connections waiting for incomplete requests.","Slowloris sends partial HTTP headers at a slow rate — just enough to keep connections alive — gradually consuming all server connection slots without generating much traffic.","Slow credential brute-force attacks target authentication systems by throttling password attempt rates; Slowloris is specifically a web server connection exhaustion technique using partial HTTP requests.","Slow network scanning is a stealth reconnaissance technique; Slowloris is a web server availability attack that exhausts HTTP connection pools, not a reconnaissance activity."]},
  {id:550,domain:G,question:"What is a security token?",options:["A physical access control card or fob used for building entry, typically using RFID or NFC technology to grant access through secured doors","A physical or software device that generates time-based one-time passwords or stores cryptographic credentials for authentication","A digital certificate permanently embedded in a hardware device during manufacturing that uniquely identifies the device and enables secure communication or device attestation","A randomly generated session identifier stored in a browser cookie that authenticates a user to a web application during an active session"],answer:1,explanation:"Hardware tokens (RSA SecurID, YubiKey) and software tokens (TOTP apps like Google Authenticator) provide the 'something you have' factor in MFA — without physical possession, authentication fails.",optionExplanations:["Building access cards are physical security tokens for facility entry; cybersecurity security tokens are authentication devices that generate one-time passwords or store cryptographic credentials.","Security tokens generate OTPs (RSA SecurID), store private keys (YubiKey), or contain smart card certificates — providing a possession factor that attackers cannot steal remotely.","Hardware-embedded device certificates are used for device identity and attestation; security tokens are authentication devices providing the possession factor through OTP generation or credential storage.","Session identifiers (cookies, JWT tokens) are software authentication artifacts maintained during active web sessions; security tokens are physical or software MFA devices providing the possession factor."]},
  {id:551,domain:O,question:"What is DevSecOps?",options:["A software development team that employs dedicated security engineers who perform code reviews and security testing separately from the main development workflow","The practice of integrating security activities throughout the DevOps pipeline, making security everyone's responsibility from development through deployment","A security operations team that adopts DevOps collaboration tools like ticketing systems and chat platforms to improve communication with software development teams","A set of hardening techniques and controls specifically applied to CI/CD pipeline infrastructure, build servers, artifact repositories, and container orchestration environments"],answer:1,explanation:"DevSecOps shifts security left — developers run SAST scans locally, CI/CD pipelines include SCA and DAST, and infrastructure code is scanned for misconfigurations before deployment.",optionExplanations:["Dedicated security engineers embedded in dev teams is a good organizational practice, but DevSecOps integrates security tools and activities into the automated pipeline itself.","DevSecOps embeds security checks (SAST, DAST, SCA, secrets scanning, IaC scanning) into every phase of the software delivery pipeline, treating security as code.","Security teams adopting DevOps tooling is a communication improvement; DevSecOps is the cultural and technical integration of security practices into every stage of the software delivery pipeline.","Hardening DevOps infrastructure is one component; DevSecOps primarily means integrating security testing and gates into the software delivery process itself, making security part of every developer's workflow."]},
  {id:552,domain:T,question:"What is a macro virus?",options:["A computer virus characterized by an extremely large file size, often carrying substantial payloads that consume significant disk space and memory upon execution","Malicious code embedded in document macros (Word, Excel) that executes when the document is opened and macros are enabled","A hardware-affecting virus that damages camera firmware or imaging equipment controllers, corrupting configuration settings and preventing proper macro photography device operation","A self-propagating network virus that exploits unpatched vulnerabilities in network services to rapidly replicate across thousands of connected systems without user interaction"],answer:1,explanation:"Macro viruses were rampant in the 1990s (Melissa virus) and have resurged through malicious Office documents — often delivered via email to bypass perimeter controls.",optionExplanations:["File size does not define macro viruses; macro viruses are defined by their use of application macro scripting languages embedded in document files.","Macro viruses embed VBA or similar scripting code in Office documents — when the recipient opens the file and enables macros, the malicious code executes, often downloading additional malware.","Photography equipment firmware attacks are OT/embedded system threats; macro viruses specifically refer to malicious VBA or similar scripting code embedded in office productivity documents.","Rapidly self-propagating network viruses are worms; macro viruses spread through infected document sharing and require the user to open the document and enable macros."]},
  {id:553,domain:A,question:"What is a security testing tool DAST (Dynamic Application Security Testing)?",options:["A security testing approach where developers actively participate in live testing sessions, watching for unexpected behavior and immediately fixing identified issues during sessions","Testing a running application by simulating attacks from the outside to find vulnerabilities that manifest at runtime, complementing SAST code analysis","A static code analysis tool integrated into the IDE that scans source code for security flaws during development, flagging issues before compilation or deployment","A specialized security assessment focused exclusively on database systems, testing for SQL injection, privilege escalation, insecure stored procedures, and configuration weaknesses"],answer:1,explanation:"DAST tools (OWASP ZAP, Burp Suite) test the application as an attacker would — finding XSS, SQL injection, authentication flaws, and configuration issues that static analysis misses.",optionExplanations:["Developer-present testing is a collaborative practice; DAST tests running applications by simulating external attack inputs, not a developer participation model.","DAST actively probes the running application — sending malicious inputs, fuzzing endpoints, and analyzing responses — finding runtime vulnerabilities that can only be detected in a live environment.","Static analysis runs on source code without execution; DAST is dynamic because it tests the running application by sending attack inputs and analyzing responses.","Database security assessments are specialized; DAST is a general web application testing methodology that can test any running application, including database-backed web apps."]},
  {id:554,domain:P,question:"What is a Subject Access Request (SAR) under GDPR?",options:["A formal request by a data subject asking an organization to stop processing or publicly sharing their personal data for specific purposes or entirely","A formal request by an individual to an organization asking what personal data the organization holds about them and how it is used","An IT service desk request submitted by employees to obtain elevated access permissions to sensitive corporate systems, databases, or restricted file shares","A formal data portability request submitted by a data subject asking an organization to transfer their personal data to a competing service in machine-readable format"],answer:1,explanation:"Organizations must respond to SARs within one month, provide a copy of all held data, explain processing purposes and legal basis, and describe any third-party recipients.",optionExplanations:["Data suppression requests invoke the right to restrict processing (Article 18) or erasure (Article 17); a SAR invokes Article 15 transparency rights to know what data is held.","A SAR invokes the GDPR Article 15 right of access — the individual receives a copy of their personal data, information about processing purposes, retention periods, and data sharing.","System access requests are IT service management processes; SARs are legal privacy rights requests under GDPR Article 15 enabling individuals to obtain copies of their personal data.","Data portability requests invoke GDPR Article 20 rights to receive and transfer personal data to another provider; SARs invoke Article 15 rights to access and review held data."]},
  {id:555,domain:G,question:"What is the purpose of IV (Initialization Vector) in encryption?",options:["The process of powering on and configuring dedicated hardware security modules or encryption accelerator cards to prepare them for cryptographic operation in the environment","A random or pseudo-random value used alongside the encryption key to ensure that encrypting the same plaintext with the same key produces different ciphertexts","The primary cryptographic parameter in a symmetric encryption scheme that determines the overall security strength and resistance to brute-force attacks on the ciphertext","A secure channel or protocol mechanism specifically designed to transmit symmetric encryption keys from one party to another during an initial key exchange or provisioning step"],answer:1,explanation:"IVs prevent patterns in encrypted output — without an IV, the same message encrypted twice produces identical ciphertext, leaking information about repeated content.",optionExplanations:["Hardware encryption initialization is a device setup process; IVs are cryptographic values injected into the encryption algorithm to ensure ciphertext uniqueness across multiple encryptions of the same data.","An IV ensures that encrypting identical plaintexts produces different ciphertexts each time — preventing traffic analysis attacks that exploit patterns in encrypted streams.","Key length determines cipher strength and resistance to brute force; IVs ensure uniqueness across encryption operations but do not affect the fundamental security level of the cipher.","Key transmission uses key exchange protocols like Diffie-Hellman or asymmetric encryption; IVs accompany ciphertext and can be transmitted in plaintext since they are not secret."]},
  {id:556,domain:O,question:"What is a security advisory?",options:["Verbal or written guidance from an independent security consultant on improving security practices, prioritizing investments, and addressing identified architectural weaknesses in a system","A formal notification about a security vulnerability or issue, typically published by vendors or security researchers, describing the vulnerability and available mitigations","A procurement recommendation document from IT or security staff suggesting the purchase of specific security software tools to address identified protection gaps","Security best-practice guidance published by government agencies like CISA or NIST providing general recommendations on securing specific technologies or industry sectors"],answer:1,explanation:"Security advisories (CVE descriptions, vendor bulletins like Microsoft Patch Tuesday) enable organizations to assess risk and prioritize patching before exploitation occurs.",optionExplanations:["Consultant advice is informal professional guidance; security advisories are formal, publicly published vulnerability notifications with CVE identifiers, affected versions, and remediation guidance.","Security advisories document discovered vulnerabilities — their scope, affected versions, CVE ID, CVSS score, and recommended mitigations — providing actionable information for security teams.","Software purchase recommendations are procurement documents; security advisories are technical vulnerability disclosures published to notify users of specific flaws and available patches.","Government security guidance provides general best-practice recommendations; security advisories are specific notifications about particular vulnerabilities in identified products, published by vendors or researchers."]},
  {id:557,domain:T,question:"What is a social engineering pretext?",options:["Introductory text appearing before the main phishing content in an email, designed to increase credibility by referencing prior legitimate communications or shared context","A fabricated scenario or false context that an attacker creates to establish trust and legitimacy when approaching a target","The initial OSINT gathering phase where attackers research target organizations and individuals using social media, LinkedIn, and public records to identify useful information","The technical preparation phase involving creating fake websites, spoofed email domains, and caller ID spoofing infrastructure before launching a social engineering campaign"],answer:1,explanation:"A convincing pretext (impersonating IT support, an auditor, a vendor, or HR) makes targets comply with requests they'd normally question — believability is the key success factor.",optionExplanations:["Email preamble is formatting and structure; a pretext is the entire false identity and fabricated scenario an attacker constructs to manipulate a target into compliance.","A pretext is the story an attacker tells — 'I'm from IT and need to verify your credentials due to a security incident' — creating a plausible reason for the unusual request.","Reconnaissance precedes pretexting by gathering information used to make the pretext believable; the pretext itself is the false scenario and identity used during the actual attack.","Technical infrastructure (fake sites, spoofed addresses) supports the attack but is separate from the pretext; the pretext is the narrative and false identity used to manipulate the target."]},
  {id:558,domain:A,question:"What is an air gap?",options:["A structural gap or void intentionally created in server room walls to accommodate cable routing, cooling airflow, and other infrastructure in secure facilities","Complete physical isolation of a network or system from untrusted networks, including the internet, achieved by having no physical or logical network connections","A vulnerability in HVAC systems or building automation networks that allows attackers to manipulate temperature controls and potentially damage sensitive IT equipment","The required physical distance that security guard personnel must maintain between each other during patrol routes to ensure adequate physical security coverage"],answer:1,explanation:"Air-gapped systems (classified networks, SCADA systems, nuclear controls) were thought impenetrable until Stuxnet demonstrated that USB drives could bridge the gap.",optionExplanations:["Physical structural gaps are construction and facilities engineering concerns; air gaps are network isolation strategies ensuring no electronic network connections exist.","An air-gapped system has absolutely no network connections to external networks — data can only move in/out through physical media (USB, CD), creating a security boundary that network-based attacks cannot cross.","HVAC security vulnerabilities are building management system concerns; air gaps are network isolation techniques with no wireless or wired connections to external networks.","Security personnel spacing is physical security operations management; air gaps are complete network isolation strategies ensuring a system has no electronic connections to external networks."]},
  {id:559,domain:P,question:"What is the purpose of a consent record under GDPR?",options:["Documenting user authentication events, session durations, and access patterns in system logs for security monitoring, audit trails, and troubleshooting access issues","Documented proof that valid consent was obtained from individuals before processing their personal data, including what was consented to, when, and how","A request log documenting every data subject access request received, including the requester's identity, the date received, and the organization's response timeline","A delivery log confirming that privacy notices and policy updates were sent to customers, including the date sent and the content of each notice version"],answer:1,explanation:"GDPR requires organizations to prove they obtained valid, specific, informed consent — consent records must capture the exact consent given, when, through what mechanism, and for what purpose.",optionExplanations:["Authentication logs record system access events for security monitoring; consent records document the legal basis for data processing by recording what individuals agreed to and when.","Consent records provide evidence for regulators that processing has a valid legal basis — they capture the consent text presented, date, mechanism (checkbox, signature), and scope of what was consented.","SAR records track rights requests for compliance tracking; consent records specifically document the collection, scope, and withdrawal of individual consent for specific data processing activities.","Privacy notice delivery records confirm communication occurred; consent records document the active, specific agreement individuals gave to particular processing activities, not just that they received a notice."]},
  {id:560,domain:G,question:"What is authenticated encryption?",options:["An encryption system that requires the user to authenticate with a password or biometric before the decryption key is released or the encrypted volume is mounted","An encryption scheme that simultaneously provides confidentiality, integrity, and authenticity — ensuring data is encrypted and that tampering can be detected","An encryption approach that uses X.509 digital certificates to authenticate communication parties before establishing an encrypted session and exchanging symmetric session keys","A security workflow that first verifies user identity through multi-factor authentication and then applies encryption to protect the data the authenticated user accesses"],answer:1,explanation:"AES-GCM (used in TLS 1.3) provides authenticated encryption — the ciphertext includes an authentication tag that detects any modification, preventing padding oracle and bit-flipping attacks.",optionExplanations:["Requiring authentication before decryption is access control over encrypted data; authenticated encryption is a cryptographic property combining confidentiality with integrity and authenticity in a single operation.","Authenticated encryption modes (AES-GCM, ChaCha20-Poly1305) provide encryption for confidentiality plus a MAC for integrity in a single operation — defeating attacks that exploit the lack of integrity checking.","Certificate-based encryption uses PKI to authenticate parties; authenticated encryption is a specific cryptographic mode like AES-GCM that combines encryption with an authentication tag in one operation.","Sequential authentication then encryption is an access control workflow; authenticated encryption is a single cryptographic operation that simultaneously provides both confidentiality and integrity protection."]},
  {id:561,domain:T,question:"What is a network-based IDS vs. a host-based IDS (HIDS)?",options:["Network IDS is implemented as software sensors on servers, while host-based IDS is implemented as dedicated hardware appliances installed at physical network access points","Network IDS monitors traffic on network segments; host IDS monitors activity on individual systems including file changes, process activity, and log events","HIDS monitors physical aspects of host security like server room access and hardware tampering, while NIDS monitors logical network security events like policy violations","Network IDS provides more accurate detection because it has full network visibility, while host IDS generates significantly more false positives due to normal system activity noise"],answer:1,explanation:"NIDS sees network patterns (port scans, protocol anomalies); HIDS sees what's actually happening on the host (files changed, new processes, log tampering) — together they provide comprehensive visibility.",optionExplanations:["Both NIDS and HIDS can be software or hardware implementations; the fundamental distinction is what they monitor, not the physical form of the implementation.","NIDS (Snort, Suricata) captures and analyzes network packets; HIDS (OSSEC, Wazuh) monitors endpoint activity — each provides visibility the other cannot.","Both monitor logical/software security events; NIDS captures and analyzes network packets while HIDS monitors operating system activity like file changes and process execution.","Detection accuracy depends on configuration and tuning, not deployment type; both NIDS and HIDS generate false positives, and neither is inherently more accurate."]},
  {id:562,domain:A,question:"What is a security orchestration playbook?",options:["A comprehensive security team training manual that documents security procedures, tool usage guides, and incident response protocols for onboarding new security operations center analysts","A documented, automated workflow that defines the step-by-step actions a SOAR platform should take in response to a specific type of security alert or incident","A strategic playbook for competing red and blue security teams in a purple team exercise, documenting attack techniques, expected detections, and validation test scenarios","A structured discussion script used to facilitate tabletop exercises where security team members walk through hypothetical incident scenarios to identify response gaps"],answer:1,explanation:"SOAR playbooks automate 95% of alert responses — looking up IP reputation, quarantining endpoints, creating tickets, and notifying analysts — reducing MTTR from hours to seconds.",optionExplanations:["Training manuals are educational documents for personnel; security orchestration playbooks are machine-executable automated workflows that drive SOAR platform responses to specific alert types.","A SOAR playbook defines triggers (alert type, severity), enrichment steps (IP lookup, user lookup), decision logic (is this malicious?), response actions (block, quarantine, notify), and documentation steps.","Security team exercise playbooks guide tabletop and purple team exercises; security orchestration playbooks are automated technical response workflows executed by SOAR platforms.","Tabletop exercise scripts guide team discussions about hypothetical scenarios; SOAR playbooks are automated technical response workflows that trigger and execute actions based on live alerts."]},
  {id:563,domain:O,question:"What is patch management and why is it critical?",options:["Physically managing patch cables, cable trays, and cable labeling in network closets and data centers to maintain organized and documented cabling infrastructure","The systematic process of identifying, acquiring, testing, and deploying security patches to remediate known vulnerabilities before they can be exploited","Fixing software defects by modifying source code during the development phase, testing the fix in development environments, and merging it into the codebase","Applying firmware updates exclusively to specialized industrial control equipment and OT devices while excluding standard IT systems from the update management process"],answer:1,explanation:"Unpatched vulnerabilities are the most common attack vector — EternalBlue (WannaCry), Log4Shell, and ProxyLogon all exploited known vulnerabilities with available patches.",optionExplanations:["Copper patch cable management is physical infrastructure organization; patch management addresses software and firmware security updates to remediate known vulnerabilities across IT systems.","Patch management includes vulnerability scanning to find unpatched systems, risk prioritization by CVSS score and exploitability, testing in non-production, and deploying patches within defined SLAs.","Code-level bug fixes during development are the development team's normal workflow; patch management applies vendor-released security patches to production systems across the operational IT environment.","Firmware management for OT devices only is a limited scope; comprehensive patch management covers all system types including servers, workstations, network devices, and specialized equipment."]},
  {id:564,domain:T,question:"What is a smurfing attack?",options:["A social engineering attack campaign that uses cartoon characters and animated graphics in phishing emails to appeal to younger or less technical targets and bypass content filters","A DDoS amplification attack that spoofs the victim's IP as the source of ICMP echo requests sent to broadcast addresses, causing many hosts to flood the victim with replies","A coordinated influence operation using multiple fictional online personas and accounts to spread disinformation, manipulate public opinion, and artificially amplify social media narratives","A targeted attack campaign orchestrated by a small cell of highly skilled threat actors who coordinate their individual actions to maximize impact on a specific organization"],answer:1,explanation:"Smurf attacks amplify traffic by spoofing the victim's IP in ping broadcasts — each ping to a /24 network generates 254 responses back to the victim.",optionExplanations:["The name 'Smurf' is colloquial and unrelated to cartoons; smurfing is a network-layer DDoS amplification attack exploiting ICMP broadcasts, not a social engineering technique.","A Smurf attack sends ICMP ping requests with the victim's spoofed source IP to network broadcast addresses — every device on the broadcast domain responds, sending amplified traffic to the victim.","Fictional persona attacks are information operations or social media manipulation; smurfing is a specific network-layer DDoS amplification technique exploiting IP spoofing and broadcast address behavior.","Attacker group size does not define smurfing; it is a specific technical attack exploiting IP broadcast amplification, achievable by a single attacker with minimal bandwidth resources."]},
  {id:565,domain:G,question:"What is a message authentication code (MAC)?",options:["The hardware MAC address of a network interface card used in 802.1X network access control to authenticate and authorize devices before granting network access","A fixed-size value computed from a message and a secret key that allows verification of both data integrity and the sender's knowledge of the secret key","A proprietary verification code appended to email messages by enterprise email security gateways to allow receiving systems to confirm the email originated from a trusted gateway","A digital signature computed using the CA's private key and appended to an X.509 certificate so that relying parties can verify the certificate's authenticity and integrity"],answer:1,explanation:"MACs (HMAC, CMAC, Poly1305) detect tampering and verify the sender has the shared secret — unlike signatures, they're symmetric, requiring both parties to share the key.",optionExplanations:["Hardware MAC addresses are Layer 2 network identifiers used for device identification; message authentication codes are cryptographic constructs that verify message integrity using a shared secret key.","A MAC is computed using a secret key shared between sender and receiver — any modification of the message produces a different MAC, enabling tampering detection.","Email authentication codes are specific implementations; a message authentication code is a general cryptographic primitive computed from both message content and a shared secret key.","Certificate signatures use asymmetric key pairs where the CA signs with its private key and anyone verifies with the public key; MACs use a single shared symmetric secret key."]},
  {id:566,domain:P,question:"What is the purpose of a data protection impact assessment (DPIA)?",options:["A business impact analysis specifically focused on how natural disasters affecting data center facilities could disrupt data availability, processing capabilities, and service delivery","A systematic process for evaluating how a processing activity impacts individuals' privacy rights and identifying measures to minimize those impacts","A post-incident analysis that quantifies the business and regulatory impact of a data breach, including affected record counts, notification obligations, and reputational damage","A technical evaluation of new storage infrastructure such as cloud object storage or NAS systems, assessing capacity, performance, redundancy, and integration requirements"],answer:1,explanation:"GDPR Article 35 requires DPIAs for high-risk processing (biometrics, large-scale surveillance, systematic profiling) before implementation, not after.",optionExplanations:["Natural disaster impact on data centers is business continuity planning; DPIAs evaluate privacy risks to individuals from planned data processing activities before those activities begin.","A DPIA systematically identifies privacy risks in a planned processing activity, assesses necessity and proportionality, and documents measures to minimize risk — required before starting high-risk processing.","Post-breach impact assessment is part of incident response; DPIAs are prospective risk assessments conducted before new processing begins, not reactive analyses after breaches occur.","Data storage system technical evaluations are infrastructure assessments; DPIAs assess the full privacy impact of processing activities on individuals' rights, covering the entire processing operation."]},
  {id:567,domain:A,question:"What is an active directory (AD) and why is it a primary attack target?",options:["An actively maintained organizational directory listing security team contacts, escalation paths, and on-call schedules for incident response and security event notifications","A Microsoft directory service managing authentication and authorization for Windows environments — a primary attack target because compromising it means controlling all domain-joined systems","A simple database table that stores records of currently active user accounts, session states, and last login timestamps for application authentication purposes","A network monitoring platform that maintains an active directory of discovered network devices, their configurations, performance metrics, and current operational status in real time"],answer:1,explanation:"Controlling Active Directory means owning the entire Windows domain — attackers pursue domain dominance, targeting Domain Admins and using tools like BloodHound to map attack paths.",optionExplanations:["Security contact directories are organizational communication resources; Active Directory is Windows identity infrastructure managing authentication, authorization, and group policy for an entire enterprise domain.","Active Directory is the identity backbone of most Windows enterprises — it stores user accounts, computer accounts, group policies, and trust relationships. Domain Admin access provides control over all domain resources.","AD does manage users but is far more than a user database; it manages authentication, authorization, group policies, computer accounts, and trust relationships across an entire Windows enterprise.","Network device monitoring platforms use SNMP and NetFlow; Active Directory manages Windows identity, authentication, and group policy enforcement across domain-joined systems."]},
  {id:568,domain:O,question:"What is a security exception process?",options:["The practice of dismissing or suppressing security alerts that analysts determine to be false positives, removing them from queues without triggering further investigation","A formal process for granting temporary or permanent exceptions to security policies when business requirements prevent full compliance, with documented justification, compensating controls, and approval","A formal escalation procedure for reporting high-severity security incidents as exceptions to standard SLA timelines, triggering executive notification and expedited response resources","A documented waiver from mandatory security awareness training requirements, granted to specific employees whose role or circumstances prevent timely training completion"],answer:1,explanation:"Exception processes prevent security debt from accumulating invisibly — requiring approval (CISO, risk committee) and compensating controls ensures risk is accepted consciously, not ignored.",optionExplanations:["Alert suppression is a security operations efficiency practice; security exceptions formally document and accept specific policy deviations with compensating controls and management approval.","Security exceptions document why a specific requirement cannot be met (legacy system, vendor limitation), what compensating controls offset the risk, who approved the exception, and when it expires.","Incident escalation procedures manage response prioritization; security exceptions proactively document known policy gaps before incidents occur, with formal risk acceptance and compensating controls.","Training requirement waivers may be one specific type of exception; security exception processes cover all policy requirements where compliance is infeasible, not just training."]},
  {id:569,domain:T,question:"What is a ZIP bomb (decompression bomb)?",options:["A fictional physical explosive device concealed inside a USB drive or storage device enclosure, designed to detonate when plugged into a computer's USB port","A malicious archive that appears small but expands to enormous size when decompressed, designed to crash or overwhelm antivirus scanners and file systems","A legitimately compressed file archive containing bomb threat documents or media files that law enforcement encounters when investigating digital evidence from suspects","A denial-of-service attack specifically targeting ZIP file servers by flooding them with malformed archive requests to exhaust server processing and memory resources"],answer:1,explanation:"42.zip is a famous example — it's 42KB compressed but expands to 4.5 petabytes, causing antivirus engines that try to scan the contents to exhaust memory and crash.",optionExplanations:["ZIP bombs are software-based attacks, not physical explosive devices; a decompression bomb is a malicious file that overwhelms software processing, not physical infrastructure.","A ZIP bomb exploits the recursive compression of small files that expand dramatically — antivirus software that tries to decompress and scan content is overwhelmed, creating a DoS condition.","Archives encountered in criminal investigations are digital evidence; decompression bombs are offensive security tools designed to crash or overwhelm software that attempts to process them.","ZIP server DoS attacks target file servers with network floods; decompression bombs target any software that automatically decompresses archives, causing resource exhaustion during extraction."]},
  {id:570,domain:G,question:"What is PKCS (Public Key Cryptography Standards)?",options:["A government-mandated standard published by NIST specifying approved public key cryptography algorithms, key sizes, and implementation requirements for federal agency use","A set of standards developed by RSA Security defining formats and protocols for public key cryptography, including key formats, certificate requests, and cryptographic message syntax","A proprietary encryption file format developed and maintained exclusively by RSA Security for encrypting data in their commercial enterprise security products","A network protocol standard defining mechanisms for distributing public keys through centralized key servers, enabling participants to publish and retrieve cryptographic public keys"],answer:1,explanation:"PKCS standards (PKCS#1 RSA, PKCS#7/CMS, PKCS#8 private key, PKCS#10 CSR, PKCS#11 HSM interface, PKCS#12 certificate bundle) are foundational to PKI interoperability.",optionExplanations:["PKCS was developed by RSA Security (now commercial); it's an industry standard, not a government mandate, though many government standards reference PKCS formats.","PKCS standards define the formats used in PKI — certificate signing requests (PKCS#10), certificate bundles (.pfx/.p12 using PKCS#12), HSM token interfaces (PKCS#11), and cryptographic message syntax.","PKCS is not proprietary to RSA's commercial products; it became the foundation for widely implemented open standards including TLS, X.509, PKCS#11 token interfaces, and certificate management.","Public key distribution protocols are key server specifications; PKCS covers many cryptographic format specifications including certificate requests, key file formats, and cryptographic message syntax."]},
  {id:571,domain:T,question:"What is a cross-site request forgery (CSRF) token?",options:["A browser-side token that blocks third-party cookies from being set by advertisements and trackers on cross-site resources, used to enforce browser privacy settings","A unique, secret, unpredictable value included in web forms that the server validates to ensure requests originate from legitimate users and not from malicious third-party sites","A bearer token used in the Authorization header of cross-origin API requests, allowing third-party applications to access protected APIs on behalf of authenticated users","A session-specific encryption token that the browser uses to encrypt sensitive form field data before transmission, ensuring form contents cannot be intercepted in plaintext"],answer:1,explanation:"CSRF tokens are embedded in forms and verified server-side — a malicious site cannot read the victim's token (same-origin policy) so it cannot forge valid requests.",optionExplanations:["Cookie-blocking tokens are browser privacy mechanisms; CSRF tokens are per-session secret values embedded in forms that servers validate to confirm requests are genuinely from their own pages.","A CSRF token is a hidden form field containing a random secret that the server ties to the user's session — attackers from other origins can't read it, so they can't include a valid token in forged requests.","API authentication tokens (OAuth bearer tokens) authorize cross-origin API access; CSRF tokens specifically prevent forged form submissions from malicious third-party websites in browser contexts.","Form data encryption is provided by HTTPS transport security; CSRF tokens are unencrypted random values that verify the request originated from the legitimate site, not from a forged cross-site request."]},
  {id:572,domain:A,question:"What is security information lifecycle management?",options:["Managing the full employment lifecycle of security personnel including hiring, onboarding, training, performance management, role transitions, and offboarding procedures","The processes governing how security-relevant information (logs, incidents, intelligence) is created, collected, analyzed, stored, and ultimately disposed of","Managing the complete lifecycle of encryption keys from generation and distribution through rotation, revocation, and secure destruction to maintain cryptographic security","A structured framework for planning and executing regular replacement cycles for security tools, appliances, and technology platforms as they reach end-of-life"],answer:1,explanation:"Information lifecycle management ensures logs are retained long enough for investigations, security data is protected from tampering, and information is disposed of securely when no longer needed.",optionExplanations:["Security personnel lifecycle is human resources management; security information lifecycle management addresses how security-relevant data like logs and incident records flows through its existence.","Managing security information through its lifecycle includes log collection policies, secure storage with integrity protection, retention periods meeting compliance requirements, and secure deletion.","Key lifecycle management is a cryptographic management process; security information lifecycle covers all security-relevant data including logs, incidents, and threat intelligence.","Technology refresh planning addresses hardware and software replacement schedules; security information lifecycle management addresses the data created and used by security tools, not the tools themselves."]},
  {id:573,domain:O,question:"What is the MITRE ATT&CK framework?",options:["A structured framework developed to assess and improve the security posture of MITRE Corporation's own internal network by mapping attack surfaces and defense gaps","A knowledge base of adversary tactics, techniques, and procedures (TTPs) based on real-world observations, used for threat modeling, detection development, and red team planning","A standardized scoring system used by penetration testers to rate discovered vulnerabilities by exploitability, impact, and severity to prioritize remediation recommendations","A governance framework for tracking, renewing, and managing cybersecurity professional certifications across a security team to ensure compliance with training requirements"],answer:1,explanation:"ATT&CK (Adversarial Tactics, Techniques & Common Knowledge) provides a common language for describing attacks — detection engineers write rules against specific technique IDs, red teams plan engagements against ATT&CK tactics.",optionExplanations:["ATT&CK was created by MITRE for the broader security community to document real-world attacker behaviors; it is not a framework targeting MITRE's own systems.","ATT&CK documents real attacker behaviors organized by tactics (why) and techniques (how) — security teams use it to assess coverage, plan detections, and communicate about threats precisely.","CVSS is the vulnerability severity scoring system; ATT&CK is a behavioral TTP knowledge base cataloging how real-world adversaries accomplish their objectives.","Certification management is a training and HR function; ATT&CK is a threat intelligence framework cataloging adversary tactics and techniques observed in real-world attacks."]},
  {id:574,domain:T,question:"What is session hijacking?",options:["Remotely taking control of a user's entire computer desktop session using remote access tools after obtaining credentials through phishing or credential theft","Stealing or forging a user's authenticated session token to impersonate them on a web application without knowing their credentials","Gaining unauthorized access to a video conferencing call by obtaining or guessing the meeting ID and passcode to eavesdrop on or disrupt the meeting","Intercepting and redirecting an authenticated user's web session to an attacker-controlled server using DNS manipulation or BGP hijacking to steal session credentials"],answer:1,explanation:"Session tokens stolen via XSS, network interception, or prediction are used to impersonate authenticated users — prevented by secure, HttpOnly, SameSite cookies and short session timeouts.",optionExplanations:["Remote desktop takeover using stolen credentials is a different attack; session hijacking specifically steals web authentication tokens to impersonate users without knowing their actual credentials.","Session hijacking captures the session cookie or token (via XSS, network sniffing, or token prediction) and uses it to make requests that appear to come from the legitimate authenticated user.","Video conference intrusion (Zoom-bombing) targets real-time communication tools; session hijacking targets web application authentication tokens to impersonate users without their credentials.","Session redirection through DNS or BGP manipulation is a network-level attack; session hijacking directly steals and replays the session token on the original application to impersonate the user."]},
  {id:575,domain:G,question:"What is the purpose of a Master Boot Record (MBR) and the UEFI threat to it?",options:["The primary bootloader application and a network-accessible vulnerability in PXE boot services that allows remote attackers to compromise systems during the boot process","The first sector of a hard drive containing partition information and bootloader code — a target for bootkits that persist below the OS level and survive reinstallation","An access log stored in the security event database that records all failed and successful master administrator password authentication attempts for auditing and intrusion detection","The primary system configuration file loaded during startup that defines operating system settings, hardware parameters, driver configurations, and network interface settings"],answer:1,explanation:"MBR bootkits (TDL4, MBRFilter target) persist even after OS reinstallation since the MBR is written before the OS. UEFI Secure Boot was designed to address this threat.",optionExplanations:["MBR vulnerability is local disk-based, not network-based; the MBR is not a bootloader application but the disk sector containing partition data and bootstrap code.","The MBR or UEFI partition table determines how the system boots — malware controlling the MBR runs before any security software, survives OS reinstallation, and is extremely difficult to detect and remove.","Password attempt logs are authentication audit records; the Master Boot Record is a specific disk sector containing partition table entries and bootstrap code, not an authentication log.","System configuration files (registry, /etc/sysctl.conf) define OS settings; the MBR is a specific 512-byte disk sector containing partition information and bootstrap code executed during system startup."]},
  {id:576,domain:P,question:"What is the principle of transparency in data privacy?",options:["Making all organizational data publicly accessible on a government open data portal or company website to promote civic engagement and public accountability","Organizations must be clear and open with individuals about how they collect, use, and share personal data in ways that are intelligible and accessible","Using publicly documented and peer-reviewed cryptographic algorithms rather than proprietary secret algorithms, following Kerckhoffs' principle that security should not depend on algorithm secrecy","Publicly disclosing security incidents and breach details to the general public as part of organizational accountability, even when not legally required to do so"],answer:1,explanation:"Transparency requires plain-language privacy notices, not legal jargon — individuals must genuinely understand what happens to their data to make meaningful choices.",optionExplanations:["Making all data publicly visible would violate confidentiality requirements and data protection principles; transparency means being open about data practices, not exposing the underlying personal data itself.","Transparency means proactively informing individuals about data practices — what's collected, why, how long, who can see it — in a clear, accessible way that enables informed decisions.","Cryptographic algorithm transparency (Kerckhoffs' principle) is a cryptographic design principle; data privacy transparency is about informing individuals how their personal data is collected, used, and shared.","Public security incident disclosure may be required in some breach notification contexts; transparency as a privacy principle broadly covers all communications about personal data practices."]},
  {id:577,domain:A,question:"What is a threat model?",options:["A behavioral profile or persona document describing a physical threat actor's motivations, capabilities, and likely tactics for conducting attacks against physical facilities","A structured analysis of an application or system that identifies potential threats, attack vectors, and necessary mitigations from an adversary's perspective","A financial analysis model that calculates expected security budgets, return on security investment, and cost-benefit ratios for proposed security control implementations","A high-level strategic description of the current network threat landscape, summarizing the categories of active threats and general trends affecting an industry sector"],answer:1,explanation:"Threat modeling (STRIDE, PASTA, DREAD) asks 'what could go wrong?' for a specific system during design — finding architectural flaws when they're cheap to fix.",optionExplanations:["Physical threat actor profiles are physical security threat intelligence; a threat model is a structured technical analysis of an application identifying security weaknesses from an adversary's view.","Threat modeling systematically identifies threats using frameworks like STRIDE (Spoofing, Tampering, Repudiation, Information Disclosure, Denial of Service, Elevation of Privilege) to find security flaws during design.","Budget planning models are financial management tools; threat models are technical security analyses that identify threats and attack vectors against specific systems using frameworks like STRIDE.","Threat landscape descriptions are strategic threat intelligence summaries; a threat model is a specific technical analysis of a defined system or application's security weaknesses."]},
  {id:578,domain:O,question:"What is a bug bounty program?",options:["An internal compensation program that provides financial bonuses or incentives to software developers who identify and fix the most bugs during development sprints","A formal program offering financial rewards to security researchers who responsibly disclose vulnerabilities in the organization's systems","A quality assurance incentive program offering rewards to QA testers who discover the most software defects during internal acceptance testing and release cycles","A government-sponsored financial incentive program offering rewards to citizens who report malware infections or cyberattack evidence to law enforcement agencies"],answer:1,explanation:"Bug bounties (HackerOne, Bugcrowd, company programs) cost less than undiscovered breaches — researchers are incentivized to report rather than exploit or sell vulnerabilities.",optionExplanations:["Internal developer bug-fixing incentives are employee performance programs; bug bounties specifically incentivize external security researchers to find and responsibly disclose security vulnerabilities.","Bug bounty programs define scope, reward tiers, and responsible disclosure requirements — paying researchers based on vulnerability severity to find issues before malicious actors do.","QA testing incentives are internal software quality programs; bug bounties engage the external security research community to find security-specific vulnerabilities before malicious actors discover them.","Government malware reporting programs may involve rewards; bug bounties are specifically private or public programs rewarding security researchers for responsibly disclosing vulnerabilities in specific systems."]},
  {id:579,domain:T,question:"What is a rootkit's persistence mechanism?",options:["Creating hidden administrative user accounts or backdoor credentials that provide continued access even after the primary compromise vector has been discovered and remediated","Hooking OS functions, modifying bootloaders, or hiding in firmware to survive OS reboots and reinstallation, maintaining persistent access","Distributing encrypted copies of itself across multiple directories and registry locations to ensure at least one copy survives partial cleanup attempts by security tools","Registering itself as a scheduled task or system service that automatically restarts the malware process whenever it is terminated or the system is rebooted"],answer:1,explanation:"Firmware rootkits (like LoJax in UEFI firmware) survive complete drive wiping and OS reinstallation because they reside in flash storage outside the operating system.",optionExplanations:["Creating backdoor accounts is a post-exploitation persistence technique for maintaining access; rootkit persistence specifically subverts the operating system itself through kernel hooks and bootloader modification.","Rootkits achieve persistence through kernel hooks, UEFI/BIOS modification, or MBR infection — ensuring they load before and survive OS-level security and reinstallation.","Multi-location file copying is a basic malware resilience technique; rootkit persistence uniquely achieves survival by modifying the OS kernel, bootloader, or firmware below the level security tools operate.","Scheduled task persistence is visible to OS security tools and easily removed; rootkits hide their persistence mechanism by subverting OS-level functions to be invisible to security tools."]},
  {id:580,domain:G,question:"What is the difference between a false positive and a false negative in security?",options:["False positives are more dangerous than false negatives","A false positive is a benign event incorrectly flagged as malicious; a false negative is a malicious event incorrectly classified as benign","They are the same type of detection error","False negatives are always rare in modern security tools"],answer:1,explanation:"Both errors have costs: false positives waste analyst time and cause alert fatigue; false negatives miss real attacks. The balance depends on sensitivity/specificity tuning.",optionExplanations:["Neither is universally more dangerous; false positives cause alert fatigue and false negatives miss real threats — both have serious consequences.","A false positive triggers unnecessary investigation (clean email blocked, legitimate file quarantined); a false negative misses a real attack (malware not detected, intrusion not alerted).","They are opposite error types — false positives flag benign events as threats; false negatives miss actual threats.","False negative rates depend heavily on tuning and novel attacks; modern tools have both types of errors, and false negatives for sophisticated attacks can be quite high."]},
  {id:581,domain:T,question:"What is a DDoS attack's distinction from a DoS attack?",options:["DDoS uses more sophisticated techniques","A DDoS (Distributed Denial of Service) attack uses many geographically distributed systems (often a botnet) to flood the target, making it much harder to block than single-source DoS","DoS attacks are always more powerful","DDoS attacks target distributed systems while DoS attacks target centralized systems"],answer:1,explanation:"DDoS attacks use thousands to millions of compromised systems — blocking one IP stops nothing; defending requires upstream scrubbing, anycast, or anti-DDoS services.",optionExplanations:["Both DoS and DDoS can use sophisticated techniques; the key distinction is the number and distribution of attack sources.","DDoS uses many attacking systems simultaneously — making source IP blocking ineffective — and generates traffic volumes that overwhelm target infrastructure.","DDoS attacks are generally more powerful due to distributed traffic volumes; DoS from a single source is easier to mitigate.","DDoS refers to the distributed source of the attack, not the nature of the target; both can target any type of system."]},
  {id:582,domain:A,question:"What is a protocol analyzer (packet sniffer)?",options:["A tool that analyzes security protocols for vulnerabilities","Software or hardware that captures and analyzes network packets flowing through a network interface, providing visibility into network communications","A tool for optimizing network protocols","A device that blocks suspicious protocols"],answer:1,explanation:"Wireshark, tcpdump, and Zeek capture packets for troubleshooting, protocol analysis, incident investigation, and security monitoring — but attackers also use them to intercept credentials.",optionExplanations:["Protocol vulnerability analysis is a different security assessment; packet sniffers capture live network traffic.","Protocol analyzers capture raw network packets and decode their protocol fields — enabling analysis of exactly what data is flowing on the network, for both legitimate and malicious purposes.","Protocol optimization is network engineering; sniffers capture and analyze traffic without modifying it.","Traffic blocking is done by firewalls and IPS; packet sniffers capture and analyze traffic passively."]},
  {id:583,domain:O,question:"What is vulnerability disclosure and coordinated disclosure?",options:["Disclosing all vulnerabilities publicly immediately","The process of reporting discovered vulnerabilities to affected vendors and allowing them time to develop and release patches before public disclosure of the vulnerability details","Disclosing vulnerabilities only to government agencies","Sharing vulnerability details with security community without vendor notification"],answer:1,explanation:"Coordinated disclosure (responsible disclosure) gives vendors typically 90 days (Google Project Zero standard) to patch before researchers publish — balancing public safety with research openness.",optionExplanations:["Immediate full disclosure is 'full disclosure'; coordinated disclosure provides vendors time to patch first.","Coordinated disclosure notifies the vendor first, establishes a patch timeline, and publishes details only after the patch is available — enabling users to protect themselves while giving vendors fair opportunity to fix.","Government-only disclosure is sometimes used for critical infrastructure vulnerabilities; standard coordinated disclosure goes to the affected vendor.","Sharing details without vendor notification is full disclosure; coordinated disclosure always involves vendor notification first."]},
  {id:584,domain:T,question:"What is an XML external entity (XXE) injection?",options:["Injecting XML into database queries","A web security vulnerability where attackers exploit XML parsers by injecting external entity references that read local files, perform SSRF, or cause denial of service","Injecting malicious entities into XML databases","An attack on XML-based authentication systems"],answer:1,explanation:"XXE exploits XML parsers that process external entity declarations — attackers can read /etc/passwd, internal network files, or make the server send requests to internal services.",optionExplanations:["Database XML injection is a different attack; XXE specifically exploits XML parser external entity processing.","XXE attacks inject external entity declarations (<!ENTITY ext SYSTEM 'file:///etc/passwd'>) that cause vulnerable XML parsers to process them, exposing sensitive files or enabling server-side request forgery.","XML database attacks are different; XXE specifically targets XML parsing functionality in web applications.","XML authentication attacks may use XXE as a technique; XXE itself is specifically about external entity processing in XML parsers."]},
  {id:585,domain:G,question:"What is the role of an Online Certificate Status Protocol (OCSP) responder?",options:["A server that issues digital certificates","A service that provides real-time certificate revocation status for a specific certificate, as an alternative to downloading the entire CRL","A protocol for online certificate renewal","A service that checks certificate expiration dates"],answer:1,explanation:"OCSP provides faster, smaller revocation checks than CRLs — OCSP stapling has the server cache and serve the OCSP response, reducing latency and improving privacy.",optionExplanations:["Certificate issuance is done by CAs; OCSP responders answer revocation status queries.","An OCSP responder receives a certificate serial number query and responds with 'good', 'revoked', or 'unknown' — providing real-time revocation status without downloading the entire CRL.","Certificate renewal is handled by the CA registration process; OCSP is specifically for revocation status checking.","OCSP checks revocation status, not expiration; certificate expiration is checked by comparing the certificate's validity period."]},
  {id:586,domain:P,question:"What is data tokenization?",options:["Creating authentication tokens for users","Replacing sensitive data with non-sensitive placeholder values (tokens) while maintaining a mapping in a secure vault, allowing systems to process tokens without accessing actual data","Converting data into token format for blockchain","Tokenizing user access rights"],answer:1,explanation:"Payment tokenization (credit card PANs replaced with tokens) means merchants never store actual card numbers — a breach of the merchant system exposes only worthless tokens.",optionExplanations:["Authentication tokens are identity management tools; data tokenization replaces sensitive data values with placeholder tokens.","Tokenization replaces sensitive values (credit card numbers, SSNs) with random tokens stored in a secure vault — the original data never leaves the vault, reducing the sensitive data footprint.","Blockchain tokenization converts assets to digital tokens; data security tokenization protects sensitive data in payment and data processing systems.","Access right tokens are authorization tokens; data tokenization is a data protection technique for sensitive values like payment card data."]},
  {id:587,domain:A,question:"What is an endpoint detection and response (EDR) platform?",options:["A platform for managing network endpoints","A security solution that continuously monitors endpoints for suspicious behavior, records detailed activity, and enables investigation and response to detected threats","An antivirus solution for endpoint devices","A platform for deploying security patches to endpoints"],answer:1,explanation:"EDR (CrowdStrike Falcon, SentinelOne, Microsoft Defender for Endpoint) records every process, file change, network connection, and registry modification — enabling threat hunting and incident response.",optionExplanations:["Endpoint management is MDM/UEM; EDR is specifically a security detection and response tool.","EDR continuously records endpoint telemetry, applies behavioral detection to identify threats, enables remote investigation and containment, and supports threat hunting — far beyond traditional antivirus.","Antivirus uses signatures and some heuristics; EDR provides comprehensive behavioral monitoring, recording, and response capabilities.","Patch deployment is patch management; EDR focuses on threat detection, investigation, and response on endpoints."]},
  {id:588,domain:O,question:"What is the role of a CISO (Chief Information Security Officer)?",options:["Managing the company's information storage","The senior executive responsible for establishing and maintaining the enterprise information security program, managing risk, and aligning security with business objectives","The head of the IT department","A compliance manager for security standards"],answer:1,explanation:"The CISO translates technical security risk into business terms for the board, owns the security strategy, manages the security team, and is accountable for the security posture.",optionExplanations:["Information storage is managed by data center and storage teams; the CISO is a strategic leadership role.","The CISO is a C-suite security executive — building security strategy, managing the security budget and team, presenting risk to the board, ensuring compliance, and making risk-based security decisions.","The IT department is typically led by a CIO or CTO; the CISO focuses specifically on security risk management.","Compliance management is one CISO responsibility; the role encompasses the entire organizational security program."]},
  {id:589,domain:T,question:"What is a malvertising attack?",options:["Advertising malware products","Injecting malicious code into legitimate advertising networks to deliver malware through ads displayed on legitimate, high-traffic websites","Creating malicious advertisements to deceive users","Advertising malware removal services fraudulently"],answer:1,explanation:"Malvertising compromises advertising networks to serve malicious ads on legitimate sites (New York Times, BBC have been affected) — users don't need to click; drive-by downloads trigger automatically.",optionExplanations:["Advertising malware products is different; malvertising uses advertising as a distribution mechanism for malware.","Malvertising buys or compromises ad inventory to serve ads containing exploit code — the ads appear on legitimate sites, reaching millions of users who trust the hosting site.","Deceptive ads are phishing-related; malvertising specifically delivers malware through compromised advertising networks on legitimate sites.","Fraudulent malware removal ads are scareware; malvertising injects actual malware delivery mechanisms into legitimate advertising networks."]},
  {id:590,domain:G,question:"What is Perfect Forward Secrecy (PFS) achieved through?",options:["Using the same session key repeatedly","Using ephemeral (temporary) key exchange (ECDHE or DHE) that generates a unique session key for each connection, ensuring past sessions remain secure if long-term keys are compromised","Distributing perfect keys across multiple servers","Using perfect hash functions for key generation"],answer:1,explanation:"ECDHE generates a new key pair for every TLS session — even if an attacker captures all TLS traffic and later steals the server private key, past sessions cannot be decrypted.",optionExplanations:["Reusing session keys eliminates forward secrecy; PFS requires a new key for each session.","PFS uses Diffie-Hellman with ephemeral keys (DHE) or its elliptic curve variant (ECDHE) — each connection generates a fresh key exchange, so recorded past sessions are protected from future key compromise.","Distributed keys don't achieve PFS; forward secrecy requires that session keys are never stored and are generated fresh for each session.","Hash functions generate digests; PFS is achieved through ephemeral asymmetric key exchange in each session."]},
  {id:591,domain:T,question:"What is a padding oracle attack?",options:["An attack that exploits oracle database padding","An attack exploiting error messages from decryption processes to decrypt ciphertext without the key, by determining if padding is valid or invalid","A brute force attack using oracle computing","An attack on blockchain smart contracts using padding"],answer:1,explanation:"POODLE and BEAST exploited padding oracle vulnerabilities in SSL/TLS — the oracle's different error responses for bad padding vs. bad MAC leaked decryption information.",optionExplanations:["Oracle database padding is unrelated; this is a cryptographic attack against cipher modes.","A padding oracle attack sends modified ciphertexts and observes whether the decryption produces valid padding — different responses to padding errors vs. MAC errors reveal bits of the plaintext.","Brute force doesn't exploit oracle-specific conditions; padding oracles exploit specific error message differences.","Smart contract attacks are blockchain security; padding oracles target symmetric encryption implementations."]},
  {id:592,domain:A,question:"What is serverless computing security?",options:["Security for servers that don't need power","Security considerations for functions-as-a-service (FaaS) where traditional server security doesn't apply — focusing on function permissions, injection attacks, and supply chain risks in dependencies","Security for virtualized servers","A security model with no servers"],answer:1,explanation:"Serverless (AWS Lambda, Azure Functions) shifts infrastructure security to the provider but creates new risks: overprivileged IAM roles, function event injection, and insecure dependencies.",optionExplanations:["Powerless servers don't exist in this context; serverless is a cloud computing model.","Serverless security addresses unique challenges: functions run with IAM roles (must follow least privilege), receive events from various sources (injection risks), and have dependencies (SCA needed).","Virtualized server security is VM security; serverless is FaaS where developers manage code, not servers.","'No servers' is the developer's perspective; servers exist but are managed by the cloud provider — security focuses on function behavior and permissions."]},
  {id:593,domain:O,question:"What is a security dashboard?",options:["A dashboard on security vehicles","A visual interface providing real-time metrics and status information about an organization's security posture, active threats, and key performance indicators","A dashboard for managing security staff schedules","A control panel for security cameras"],answer:1,explanation:"Security dashboards (in SIEM, SOC platforms) aggregate metrics like open incidents, vulnerability counts, patch compliance, and detection rate — enabling rapid situational awareness.",optionExplanations:["Security vehicle dashboards are physical; security dashboards are digital monitoring displays.","A security dashboard consolidates metrics from multiple security tools into a single view — showing alert trends, incident status, compliance metrics, and key risk indicators for situational awareness.","Staff scheduling is workforce management; security dashboards focus on technical security posture metrics.","Camera control panels are physical security systems; security dashboards aggregate cybersecurity operational metrics."]},
  {id:594,domain:P,question:"What is privacy-preserving analytics?",options:["Conducting analytics privately in secret","Techniques that enable analysis of data to extract insights without exposing individual personal data — including differential privacy, homomorphic encryption, and federated learning","Analytics on private company data","Removing personal data after analytics are complete"],answer:1,explanation:"Differential privacy (used by Apple, Google for telemetry) adds calibrated noise to aggregate results, preventing individual re-identification while preserving statistical accuracy.",optionExplanations:["Secret analytics is just non-disclosed analysis; privacy-preserving analytics uses mathematical techniques to protect individual data.","Privacy-preserving techniques (differential privacy, secure multi-party computation, federated learning) enable useful data analysis while providing mathematical guarantees that individuals cannot be identified.","Analytics on any company data doesn't address privacy preservation; privacy-preserving analytics specifically protects personal data within analytical processes.","Removing data after analysis doesn't help if analysis itself exposed personal data; privacy-preserving techniques protect during analysis."]},
  {id:595,domain:G,question:"What is a trojan access tool (RAT — Remote Access Trojan)?",options:["A tool for accessing remote servers legitimately","Malware that provides attackers with full remote control over a compromised system including file access, command execution, screen viewing, keylogging, and webcam activation","A legitimate remote desktop protocol tool","A tool for accessing trojans remotely for analysis"],answer:1,explanation:"RATs (DarkComet, njRAT, Poison Ivy) provide attackers complete access — they can see the screen, record keystrokes, access files, and use the system as a platform for further attacks.",optionExplanations:["Legitimate remote server access is SSH, RDP; RATs are malicious covert remote access tools.","A RAT installs a covert backdoor giving attackers full system control — essentially complete ownership of the victim system from a remote location, without the user's knowledge.","Remote desktop tools (RDP, VNC) are legitimate tools; RATs are malicious software with the same technical capability but installed without consent.","Analyzing trojans remotely is a malware analysis activity; RATs are the malware itself providing remote access to attackers."]},
  {id:596,domain:T,question:"What is BGP (Border Gateway Protocol) security risk?",options:["BGP creates security vulnerabilities in routers","BGP lacks built-in authentication, making it susceptible to route hijacking where attackers advertise more specific routes to redirect internet traffic","BGP is a deprecated insecure protocol","BGP security risks are only theoretical"],answer:1,explanation:"BGP route hijacking (like the 2008 Pakistan Telecom incident that took down YouTube globally) exploits BGP's trust model — RPKI (Resource Public Key Infrastructure) is the primary mitigation.",optionExplanations:["BGP is a routing protocol creating routing vulnerabilities, not arbitrary router vulnerabilities.","BGP was designed in an era of trust between ISPs — it has no cryptographic authentication of route announcements, allowing any AS to announce routes for IP prefixes they don't own.","BGP is still the internet's primary inter-domain routing protocol; its security risks are very real and actively exploited.","BGP route hijacking has been demonstrated repeatedly with real-world internet traffic impacts; the risks are practical and ongoing."]},
  {id:597,domain:A,question:"What is a security boundary?",options:["A physical boundary around a data center","A defined point where security policies, controls, and trust levels change — such as the boundary between a trusted internal network and an untrusted external network","A boundary for security team responsibilities","A regulatory boundary defining security requirements"],answer:1,explanation:"Security boundaries determine where controls must be applied — firewalls at network boundaries, data classification at data access boundaries, encryption at transmission boundaries.",optionExplanations:["Physical perimeters are physical security boundaries; security boundaries can be logical or physical.","Security boundaries are defined points where the security context changes — between security zones, trust levels, or administrative domains — requiring security controls at those transition points.","Responsibility boundaries are organizational; security boundaries are architectural points requiring controls.","Regulatory boundaries define compliance scope; security boundaries are the architectural points where different security requirements apply."]},
  {id:598,domain:O,question:"What is a security control framework?",options:["A physical framework for security equipment","A structured collection of security controls organized into categories that organizations can implement to achieve security objectives and comply with regulations","A framework for managing security software","A government regulatory framework for security"],answer:1,explanation:"CIS Controls, NIST 800-53, ISO 27001 Annex A provide control catalogs — organizations select and implement controls based on risk and compliance requirements.",optionExplanations:["Physical equipment frameworks are rack systems; security control frameworks are collections of security requirements.","Control frameworks (CIS Controls, NIST SP 800-53) provide libraries of technical, operational, and management controls that organizations select from to build security programs.","Security software management is a subset; control frameworks address the entire range of organizational security activities.","Government frameworks (NIST, FedRAMP) are regulatory; many control frameworks are voluntary industry standards applicable regardless of regulation."]},
  {id:599,domain:T,question:"What is a race condition vulnerability?",options:["A vulnerability in racing game software","A software vulnerability where the outcome of events depends on the sequence or timing of operations, allowing attackers to manipulate timing to gain unauthorized access or corrupt data","A performance vulnerability causing system slowdown","A vulnerability triggered by multiple simultaneous requests"],answer:1,explanation:"TOCTOU (Time of Check to Time of Use) race conditions occur when security checks and resource use have a window an attacker can exploit — changing a file between the check and the use.",optionExplanations:["Racing game software vulnerabilities are domain-specific; race conditions are a class of concurrency security bugs.","Race conditions occur when multiple processes or threads access shared resources without proper synchronization — an attacker can win the race by manipulating timing between check and use.","Performance issues are optimization problems; race conditions are security vulnerabilities that can lead to privilege escalation or data corruption.","Multiple simultaneous requests can trigger race conditions but the vulnerability is specifically about timing-dependent security checks and resource access."]},
  {id:600,domain:G,question:"What is security through obscurity?",options:["A valid security strategy relying on secrecy of implementation","Relying on the secrecy of system design or implementation details as the primary security mechanism — widely considered insufficient since determined attackers can discover hidden details","Encrypting security tool configurations","Using obscure security protocols"],answer:1,explanation:"Kerckhoffs' principle states security should depend only on key secrecy, not algorithm obscurity — attackers can reverse-engineer systems, but they can't steal a well-protected key.",optionExplanations:["Security through obscurity is generally considered insufficient; it can supplement but not replace real security controls.","Relying on attackers not knowing how your system works is fragile — source code leaks, reverse engineering, and insider knowledge all defeat obscurity. Real security works even when the design is known.","Encrypting configurations is a legitimate security practice; security through obscurity refers to the overall design philosophy of hiding implementation details as the primary defense.","Using non-standard protocols is one form of security through obscurity; the concept broadly means depending on implementation secrecy rather than proven cryptographic mechanisms."]},
  {id:601,domain:T,question:"What is a watering hole malware delivery chain?",options:["Delivering malware through water system networks","Attackers compromise a legitimate website, inject exploit code, users visit the site and are automatically infected — without any email or social engineering required","Infecting water treatment systems with malware","Delivering malware through streaming services"],answer:1,explanation:"APT groups use watering holes for targeted attacks — compromising industry-specific sites (security conference sites, defense contractor portals) to reach specific targets.",optionExplanations:["Water system network attacks are OT/ICS attacks; watering holes are web-based delivery mechanisms.","The watering hole chain: attacker finds sites the target frequents → compromises those sites → inserts exploit code → victim visits, gets auto-infected. No user action beyond visiting the known site required.","Water treatment systems are OT targets; watering hole attacks target websites that specific victim groups visit.","Streaming services can theoretically be used as watering holes, but the technique refers to compromising any frequently visited websites to infect target users."]},
  {id:602,domain:A,question:"What is a hardware-based VPN vs. software-based VPN?",options:["Hardware VPNs are more expensive; software VPNs are cheaper","Hardware VPNs use dedicated appliances for higher throughput and reliability; software VPNs run on general-purpose hardware and are more flexible and lower cost","Hardware VPNs are more secure; software VPNs are less secure","They use different protocols and cannot interoperate"],answer:1,explanation:"Hardware VPNs (Cisco ASA, Palo Alto) handle high-throughput enterprise connections; software VPNs (OpenVPN, WireGuard) offer flexibility and lower cost for smaller deployments.",optionExplanations:["Cost differences are real but not the primary technical distinction; performance and flexibility are the key tradeoffs.","Hardware VPN appliances have dedicated encryption processors enabling high throughput at low latency; software VPNs run on CPUs and share processing resources with other workloads.","Both hardware and software VPNs can use equivalent cryptography; security depends on configuration and protocol, not hardware vs. software.","Hardware and software VPNs generally use standard protocols (IPsec, SSL/TLS) enabling interoperability across implementations."]},
  {id:603,domain:O,question:"What is the difference between a vulnerability assessment and a risk assessment?",options:["They are the same type of assessment","A vulnerability assessment identifies technical weaknesses in systems; a risk assessment evaluates the potential business impact and likelihood of threats exploiting those weaknesses","Risk assessments are conducted only annually; vulnerability assessments are continuous","Vulnerability assessments are more comprehensive than risk assessments"],answer:1,explanation:"Vulnerability assessments find the 'what' (SQL injection in the web app); risk assessments determine the 'so what' (potential for customer data breach with regulatory and reputational impact).",optionExplanations:["Vulnerability and risk assessments are complementary but distinct processes with different scopes and outputs.","Vulnerability assessment produces a technical list of weaknesses; risk assessment translates those weaknesses into business risk by considering threat likelihood, potential impact, and existing mitigating controls.","Frequency depends on organizational policy; they are distinct types of assessments that can be conducted independently.","Risk assessments are broader in business scope while vulnerability assessments are deeper in technical scope; neither is universally more comprehensive."]},
  {id:604,domain:T,question:"What is a time-of-check to time-of-use (TOCTOU) race condition?",options:["Checking the time before using a system","A security flaw where a security check and the subsequent resource use are not atomic, allowing an attacker to change the resource between check and use","A timing attack on authentication systems","A vulnerability in time synchronization protocols"],answer:1,explanation:"Classic example: a program checks if file is readable, then reads it — attacker swaps a symlink between check and read, causing the program to read a sensitive file with elevated privileges.",optionExplanations:["System time checking is a different operation; TOCTOU is about the security gap between verification and action.","TOCTOU exploits the time gap between verifying a condition (check) and acting on it (use) — the state changes between check and use, invalidating the security verification.","Authentication timing attacks measure response time to guess credentials; TOCTOU is about resource state changes between security checks.","Time synchronization protocol vulnerabilities are different; TOCTOU exploits the non-atomic nature of check-then-use operations."]},
  {id:605,domain:G,question:"What is the role of a trust anchor in PKI?",options:["The most trusted certificate in a hierarchy","A trust anchor is a certificate or public key that is implicitly trusted by the relying party — the root CA certificates in browser trust stores are trust anchors","A trusted third party that anchors business relationships","The lowest trust level in a PKI hierarchy"],answer:1,explanation:"Browsers ship with ~100 trusted root CAs — each is a trust anchor. Compromise of a root CA (like DigiNotar in 2011) undermines trust in all certificates it issued.",optionExplanations:["Trust anchors are at the top of the trust hierarchy; the most trusted certificate IS the trust anchor (root CA).","A trust anchor is a certificate or public key that is accepted as trustworthy without further verification — browser root stores contain the trust anchors that form the basis for all TLS certificate validation.","Business relationship anchoring is a different concept; trust anchors in PKI are cryptographic trust foundations.","Trust anchors are the highest trust level; lower-level certificates derive trust from the anchor through certificate chains."]},
  {id:606,domain:P,question:"What is a legitimate interest assessment (LIA)?",options:["An assessment of a company's market legitimacy","A structured evaluation required before relying on legitimate interest as the legal basis for processing personal data, balancing the organization's interests against individual privacy rights","A legal review of business interests","An interest rate assessment for financial data processing"],answer:1,explanation:"A proper LIA documents the processing purpose, confirms no less-intrusive alternative exists, and demonstrates that privacy-respecting individuals would expect this processing.",optionExplanations:["Market legitimacy is a business concept; LIA is a specific GDPR compliance process.","An LIA involves three stages: purpose test (identifying a genuine, legitimate interest), necessity test (confirming processing is needed), and balancing test (weighing against individuals' interests and rights).","Legal business review is corporate governance; LIA is specific to GDPR's legitimate interest legal basis determination.","Financial interest rates are unrelated; LIA assesses whether the legitimate interest basis applies to personal data processing activities."]},
  {id:607,domain:A,question:"What is network traffic shaping in security?",options:["Physically shaping network cable routes","Controlling the volume and type of network traffic to limit the bandwidth available for certain applications, potentially reducing the effectiveness of bandwidth-consuming attacks","Shaping network policies for different user groups","Optimizing network packet shapes for efficiency"],answer:1,explanation:"Traffic shaping (QoS controls) can limit bandwidth available to DDoS traffic, prioritize critical business traffic during attacks, and restrict high-bandwidth applications from consuming all capacity.",optionExplanations:["Cable routing is physical network design; traffic shaping controls the flow characteristics of network traffic.","Traffic shaping uses rate limiting, QoS queuing, and bandwidth allocation to control traffic flows — limiting the bandwidth attackers or non-critical applications can consume.","User group policies are access control; traffic shaping is specifically about bandwidth and flow characteristics.","Packet structure optimization is network protocol engineering; traffic shaping manages traffic volume and priority."]},
  {id:608,domain:O,question:"What is security metrics benchmarking?",options:["Testing security tool performance benchmarks","Comparing an organization's security metrics against industry peers, standards, or best practices to understand relative performance and identify improvement opportunities","A performance benchmark for security software","Measuring security team performance against competitors"],answer:1,explanation:"Benchmarking shows whether 72-hour average patching time is good or poor for the industry — peer comparison motivates improvement and helps justify security budget to executives.",optionExplanations:["Tool performance testing is vendor evaluation; metrics benchmarking compares organizational security performance.","Security benchmarking uses survey data, industry reports, and maturity models to compare your metrics (patch time, MTTD, click rates) against peers — identifying gaps and best practices.","Software performance benchmarks are capacity planning tools; security metrics benchmarking measures program effectiveness.","Team performance comparison is HR analytics; security metrics benchmarking focuses on technical security outcomes."]},
  {id:609,domain:T,question:"What is a pharming attack's primary defense?",options:["Using antivirus software","DNSSEC implementation, which adds cryptographic signatures to DNS records enabling recipients to verify the integrity and authenticity of DNS responses","Using a VPN service","Enabling two-factor authentication"],answer:1,explanation:"DNSSEC (DNS Security Extensions) signs DNS records so resolvers can detect tampered or forged DNS responses — defeating DNS cache poisoning and pharming at the protocol level.",optionExplanations:["Antivirus doesn't protect against DNS manipulation; DNSSEC addresses the root cause.","DNSSEC adds cryptographic signatures to DNS zones, allowing resolvers to verify that DNS responses haven't been tampered with — preventing the DNS poisoning that enables pharming.","VPNs protect traffic routing but don't prevent DNS poisoning at the resolver level; DNSSEC is the protocol-level defense.","2FA protects accounts after credential entry on a phishing site; DNSSEC prevents victims from reaching the malicious site by protecting DNS integrity."]},
  {id:610,domain:G,question:"What is a cryptographic hash collision?",options:["When two encryption algorithms produce the same result","When two different input values produce identical hash output, potentially enabling digital signature forgery and integrity check bypass","A mathematical error in hash computation","When a hash function produces the same output repeatedly"],answer:1,explanation:"SHA-1 collision was demonstrated in 2017 (SHAttered) — two different PDF files with identical SHA-1 hashes. This enabled forged digital signatures, leading to SHA-1 deprecation.",optionExplanations:["Different algorithms producing the same result is a different concept; collision is about a single algorithm producing the same hash for different inputs.","A collision defeats hash function properties — if two messages share a hash, a signature on one is also valid for the other, enabling document forgery without breaking the underlying cryptography.","Mathematical errors produce incorrect outputs; collisions are when a function correctly produces the same output for different inputs.","Repeated same output could indicate a broken RNG; hash collisions are when different inputs map to the same digest value."]},
  {id:611,domain:T,question:"What is a network worm?",options:["A tool for monitoring network traffic","Self-replicating malware that spreads across networks by exploiting vulnerabilities without requiring user interaction, consuming bandwidth and system resources","A network cable management solution","A physical insect affecting network infrastructure"],answer:1,explanation:"WannaCry used the EternalBlue SMB exploit to self-propagate across networks — infecting unpatched systems without any user action, creating massive parallel ransomware outbreaks.",optionExplanations:["Network traffic monitoring is a security monitoring function; worms are malware that self-propagate.","Network worms autonomously scan for vulnerable systems, exploit them, and copy themselves to the new host — potentially infecting millions of systems in hours without any user interaction.","Cable management is physical infrastructure; worms are malicious self-replicating software.","Physical insects affecting cabling are physical security issues; network worms are malicious software."]},
  {id:612,domain:A,question:"What is vulnerability scanning vs. penetration testing?",options:["They are the same process with different names","Vulnerability scanning automatically identifies potential weaknesses; penetration testing manually exploits those weaknesses to demonstrate actual impact and risk","Scanning is more thorough than penetration testing","Penetration testing is performed only by automated tools"],answer:1,explanation:"Scanning finds potential vulnerabilities (false positives possible); penetration testing confirms exploitability and impact (false positive elimination, actual risk demonstration).",optionExplanations:["Vulnerability scanning and penetration testing are distinct activities with different outputs and purposes.","Scanners (Nessus, Qualys) find potential vulnerabilities using signatures and checks; penetration testers manually exploit vulnerabilities to prove they're real and demonstrate business impact.","Penetration testing is more thorough in demonstrating impact; scanning covers more systems quickly. Neither is universally more thorough.","Penetration testing involves skilled human testers; it's not automated — automation tools support testers but cannot replace the creativity and judgment of skilled humans."]},
  {id:613,domain:O,question:"What is an information security management system (ISMS)?",options:["A system for managing security software","A systematic framework for establishing, implementing, maintaining, and improving information security based on risk management — ISO 27001 defines ISMS requirements","A management interface for security tools","A system for tracking security incidents"],answer:1,explanation:"An ISMS (ISO 27001) provides governance structure: policies, risk management, asset management, controls, incident management, and continual improvement through PDCA cycles.",optionExplanations:["Security software management is IT operations; an ISMS is the overarching security management framework.","ISO 27001 defines ISMS requirements — governance, risk assessment, control selection, documentation, measurement, and management review — creating a comprehensive, auditable security management system.","Security tool interfaces are individual systems; an ISMS is the governance framework governing all security activities.","Incident tracking is one ISMS component; the ISMS encompasses the entire security management lifecycle."]},
  {id:614,domain:P,question:"What is data residency?",options:["Where data 'resides' in a database schema","Requirements specifying that personal data must be physically stored within specific geographic boundaries or jurisdictions, often driven by local laws","How long data remains in a system","The residence address of data subjects"],answer:1,explanation:"Data residency requirements (Russia's Federal Law 149-FZ, China's data localization laws) require personal data to be stored on servers located within the country — affecting multinational cloud deployments.",optionExplanations:["Database schema location is data architecture; residency concerns the physical geographic location of storage.","Data residency requirements mandate that data be stored within specific countries or regions — affecting cloud deployment decisions, data center locations, and multinational data management strategies.","Storage duration is data retention; residency concerns geographic location of storage.","Subject addresses are personal data; data residency refers to where the organization must physically store data about those subjects."]},
  {id:615,domain:G,question:"What is a certificate chain of trust?",options:["A chain of physical certificates","The hierarchical structure from root CA through intermediate CAs to end-entity certificates, where each certificate is signed by the one above it, establishing trustworthiness through verified signatures","A list of trusted certificates in a browser","A network chain for certificate distribution"],answer:1,explanation:"Browsers trust root CAs → root CAs sign intermediate CAs → intermediate CAs sign website certificates — the chain enables trust without having every website cert directly signed by a root CA.",optionExplanations:["Physical certificate chains don't exist in PKI; the chain is a cryptographic trust hierarchy.","A certificate chain works by having each certificate signed by a CA above it in the hierarchy — browsers verify the entire chain up to a trusted root, ensuring each certificate derives trust from a verified source.","Browser trust stores contain root CA certificates; the chain of trust is the hierarchical structure connecting those roots to individual website certificates.","Certificate distribution networks are CDN-like infrastructure; the chain of trust is a cryptographic verification structure."]},
  {id:616,domain:T,question:"What is a blended threat?",options:["An attack exclusively using multiple coordinated network-layer techniques such as flood traffic and protocol exploitation to simultaneously overwhelm different infrastructure components","An attack combining multiple attack techniques (malware, exploit, social engineering) to compromise security in ways a single technique alone couldn't achieve","An attack that simultaneously targets both physical access controls and digital network infrastructure, requiring attackers to coordinate across physical and cyber domains","A coordinated campaign where multiple distinct threat actor groups independently target the same organization at the same time without sharing tools, access, or intelligence with each other"],answer:1,explanation:"Modern APT attacks blend spear phishing (delivery) with zero-day exploits (installation) with legitimate tools (persistence) with encrypted C2 (communication) — no single control addresses all aspects.",optionExplanations:["Multiple network layer attacks describe volumetric or protocol DDoS techniques; blended threats combine fundamentally different attack categories like malware, social engineering, and exploit code.","Blended threats use multiple techniques in combination — phishing delivers a macro that exploits an Office vulnerability, installs a Cobalt Strike beacon, uses legitimate tools for lateral movement, and exfiltrates through DNS tunneling.","Hybrid physical-digital attacks are a related concept but differ from blended threats, which specifically combine multiple distinct digital attack techniques like malware delivery, exploits, and social engineering.","Multiple simultaneous independent threat actors describe coincidental or parallel campaigns; blended threats are a single coordinated attack combining diverse techniques — not multiple unrelated attackers."]},
  {id:617,domain:A,question:"What is a secure coding standard?",options:["A compliance framework specifying physical and logical security requirements for software development environments, including workstation hardening, code repository access controls, and CI/CD pipeline protection","Defined rules and guidelines for developers to follow when writing code to prevent common security vulnerabilities, such as OWASP, CERT, or CWE standards","A regulatory standard specifying minimum hardware security configurations, full-disk encryption settings, screen-lock timeouts, and removable media controls for developer workstations handling sensitive source code","A professional certification awarded to software developers who pass a vendor-neutral security exam, demonstrating knowledge of threat modeling, secure architecture, cryptography, and application security testing"],answer:1,explanation:"OWASP Top 10 coding guidance, CERT Secure Coding Standards, and CWE (Common Weakness Enumeration) provide specific rules preventing SQL injection, buffer overflows, and other common vulnerabilities.",optionExplanations:["Development environment security frameworks address infrastructure security; secure coding standards govern the code itself — the rules developers follow to avoid writing vulnerable code in the first place.","Secure coding standards like CERT C/C++ or OWASP provide concrete rules: always use parameterized queries, never use gets(), validate all input, handle errors securely — preventing classes of vulnerabilities.","Developer workstation security standards address endpoint hardening; secure coding standards govern the software being written — rules like parameterized queries, input validation, and error handling practices.","Security certifications like CSSLP validate developer knowledge; secure coding standards are the specific technical rules and practices developers follow to prevent vulnerabilities in the code they write."]},
  {id:618,domain:O,question:"What is a network flow record (NetFlow, IPFIX)?",options:["A structured log documenting physical Ethernet cable runs, patch panel connections, and conduit routes throughout a facility, used by network engineers for infrastructure change management and documentation","Aggregated network communication data capturing source/destination IPs, ports, protocols, bytes, and timing without capturing payload content — used for network visibility and security analysis","A visual network topology diagram depicting the physical paths that traffic takes between buildings, floors, and data centers, used by network architects for capacity planning and infrastructure documentation","Full packet capture data that includes the complete payload of every frame traversing a network segment, written to disk at wire speed for deep content inspection and forensic analysis"],answer:1,explanation:"Flow records (NetFlow, sFlow, IPFIX) enable 'who talked to whom, when, and how much' analysis at scale — impossible with full packet capture but sufficient to detect C2 beaconing, scanning, and data exfiltration.",optionExplanations:["Physical cable routing logs are infrastructure documentation maintained by facilities teams; flow records are automatically generated metadata about network communications between IP endpoints.","Flow records capture communication metadata — IP addresses, ports, bytes transferred, duration — providing visibility into network behavior patterns without the storage cost of full packet capture.","Physical traffic path diagrams are network topology documentation; flow records are automatically collected metadata capturing real-time communication statistics without representing physical infrastructure layout.","Full packet capture includes payload content and can reconstruct session data; flow records capture only communication metadata — IPs, ports, byte counts, and timing — without storing payload content."]},
  {id:619,domain:P,question:"What is the right to restriction of processing under GDPR?",options:["The GDPR right for individuals to withdraw consent at any time, immediately requiring organizations to cease all further collection and active processing of that person's personal data going forward","An individual's right to request that processing of their personal data is limited while a dispute about accuracy, lawfulness, or objection is resolved","A GDPR principle requiring organizations to proactively define and enforce maximum retention schedules for personal data categories, automatically purging records once the defined retention period has expired","A GDPR right enabling individuals to designate which specific employees within an organization are authorized to access, view, or process their stored personal data records on an ongoing basis"],answer:1,explanation:"GDPR Article 18 allows data subjects to have their data 'frozen' during disputes — the data can't be deleted or further processed until the restriction is lifted.",optionExplanations:["Consent withdrawal stops future processing based on consent; restriction of processing temporarily pauses all processing of already-collected data while a specific dispute about accuracy or lawfulness is being investigated.","Restriction of processing means the organization cannot process the data (except store it) while a dispute is pending — the data is 'quarantined' from use during investigation of a complaint or inaccuracy claim.","Storage limitation governs how long data can be retained; restriction of processing is a separate right that temporarily freezes how existing data can be used while a dispute or complaint is being resolved.","Controlling internal access permissions is an organizational data governance matter; restriction of processing is a data subject right that pauses the controller's ability to use the data during a pending dispute."]},
  {id:620,domain:G,question:"What is an end-entity certificate?",options:["A TLS server certificate issued to the terminal application tier in a multi-tier web architecture, used exclusively to authenticate and encrypt API calls between application servers in the backend layer","The certificate issued to a specific entity (web server, person, device) at the bottom of the PKI trust hierarchy, which cannot sign other certificates","A specialized X.509 certificate with an extended key usage extension that restricts its use exclusively to protecting email message confidentiality and integrity via the S/MIME protocol","A certificate in a PKI hierarchy that has been placed on administrative hold by the issuing CA, preventing revocation processing until a formal review determines whether permanent revocation is warranted"],answer:1,explanation:"End-entity (leaf) certificates are issued to specific subjects (websites, users, code signing) and are constrained from signing other certificates — unlike intermediate CAs which can issue certificates.",optionExplanations:["Backend API certificates are end-entity certificates but the term specifically describes the leaf position in the PKI hierarchy — any certificate issued to a specific subject that cannot sign other certificates.","End-entity certificates are constrained with 'CA:false' in the Basic Constraints extension — they identify a specific entity (website, person, device) and cannot be used to issue further certificates.","S/MIME email certificates are one type of end-entity certificate; end-entity certificates encompass all leaf certificates including web server, code signing, client authentication, and device certificates.","Certificate hold status is a temporary revocation state; end-entity certificates are defined by their position at the bottom of the trust hierarchy and their inability to sign or issue other certificates."]},
  {id:621,domain:O,question:"What is a security assessment scope?",options:["The physical territory and response jurisdiction assigned to a security team, defining which building zones, parking areas, and perimeter sections fall under their patrol routes and surveillance responsibility","The defined boundaries of a security assessment specifying what systems, networks, applications, and tests are included or excluded — preventing unauthorized testing","The organizational division of security responsibilities across teams, defining which group owns firewalls, identity management, endpoint security, cloud security, and application security within the enterprise","The geographic and network regions from which a SIEM platform collects log data, defining which endpoints, servers, network devices, and applications feed telemetry into the security operations center"],answer:1,explanation:"Scope defines what's authorized — testing systems outside scope is unauthorized access. Scoping must be explicit in writing to protect testers legally and focus testing efforts.",optionExplanations:["Physical patrol territories are physical security planning; assessment scope is a formal legal boundary document authorizing specific penetration testing or audit activities against defined digital targets.","Assessment scope formally authorizes specific testing activities against defined targets — unsigned scope documents leave testers legally exposed and testing may disrupt out-of-scope business systems.","Organizational RACI charts define team responsibilities; security assessment scope is the specific authorized boundary for a particular engagement — defining what can be tested, not who manages what.","SIEM coverage defines monitoring visibility; assessment scope is the authorized boundary for active testing — defining what systems testers may probe, attack, or enumerate without constituting unauthorized access."]},
  {id:622,domain:T,question:"What is a supply chain attack vector distinction from other attacks?",options:["Attackers physically intercept goods in transit and tamper with hardware components, network devices, or firmware before delivery, inserting malicious implants during the shipping phase between manufacturer and buyer","Attackers compromise trusted software, hardware, or services that targets rely on and install/use, exploiting the trust relationship between vendors and customers","Attackers launch simultaneous coordinated campaigns against multiple competing suppliers in the same industry segment, aiming to degrade an entire product category's security posture rather than targeting one victim","Attackers compromise an organization's procurement department or vendor payment systems to intercept and redirect financial transactions, diverting invoice payments to fraudulent accounts controlled by threat actors"],answer:1,explanation:"Supply chain attacks are uniquely powerful because they exploit trust — targets don't scrutinize software from their trusted vendors the same way they'd scrutinize unknown software.",optionExplanations:["Physical hardware interdiction during shipping is a hardware supply chain attack; the defining characteristic of software supply chain attacks is exploiting trusted vendor relationships through compromised code or services.","Supply chain attacks (SolarWinds, XZ Utils, NPM package hijacking) reach final targets through vendors those targets trust and install software from — bypassing normal security scrutiny.","Targeting multiple suppliers simultaneously describes a broad campaign; the distinguishing characteristic is exploiting the trust relationship customers place in trusted software vendors — not the breadth of suppliers targeted.","Financial fraud through procurement is business email compromise; supply chain attacks exploit the technical trust customers place in software, hardware, or services their vendors provide and they install."]},
  {id:623,domain:A,question:"What is a software bill of materials (SBOM)?",options:["An itemized financial invoice detailing software licensing fees, maintenance subscription costs, and integration service charges associated with all commercial software products an organization has procured","A formal, machine-readable inventory of all components, dependencies, and licenses in a software product — enabling vulnerability management and license compliance","A list of development tools, compilers, integrated development environments, and software frameworks that a development team has procured and installed on their workstation build environments","An itemized invoice submitted by a third-party security firm detailing penetration testing hours, vulnerability assessment deliverables, and remediation consulting fees charged for a software security engagement"],answer:1,explanation:"Biden's 2021 Executive Order required SBOMs for federal software — Log4Shell demonstrated why: organizations couldn't tell which of their products used Log4j without an SBOM.",optionExplanations:["Software procurement invoices are financial records; an SBOM is a technical inventory of software components, libraries, and dependencies that enable vulnerability identification and license compliance auditing.","An SBOM lists every library, framework, and dependency used in software, enabling rapid identification of which products are affected by newly disclosed vulnerabilities in specific components.","Build environment tool inventories are IT asset records; SBOMs document the components embedded within finished software products — the libraries, open-source packages, and dependencies shipped to customers.","Security assessment invoices are vendor billing records; an SBOM is a technical transparency document listing every dependency in a software product to support vulnerability management and supply chain risk."]},
  {id:624,domain:P,question:"What is cross-border data transfer under GDPR's adequacy decision?",options:["A network engineering determination that available bandwidth, latency, and throughput between two geographically separated data centers is sufficient to support anticipated cross-border data replication workloads","A formal decision by the European Commission that a third country provides an adequate level of data protection, enabling personal data transfer without additional safeguards","An internal self-assessment performed by an organization concluding that its existing technical and administrative controls meet an appropriate security level for conducting international personal data transfers","A mutual legal assistance treaty negotiated bilaterally between two individual nations to facilitate law enforcement evidence sharing and compel cross-border disclosure of electronic data in criminal investigations"],answer:1,explanation:"EU adequacy decisions (UK, Japan, Canada, etc.) permit free data flow similar to within the EU — without adequacy, organizations need SCCs, BCRs, or other transfer mechanisms.",optionExplanations:["Bandwidth capacity decisions are network engineering concerns; adequacy decisions are formal European Commission legal determinations about whether a third country's data protection framework is equivalent to GDPR standards.","The European Commission evaluates whether a country's legal framework provides equivalent protection to GDPR — if adequate, personal data can flow there freely; if not, additional safeguards are required.","Self-assessed data security levels are internal compliance reviews; adequacy decisions are formal European Commission rulings about a country's entire legal data protection framework, not individual organization assessments.","MLATs facilitate law enforcement cooperation; adequacy decisions are European Commission determinations allowing commercial personal data transfers between the EU and countries providing equivalent data protection levels."]},
  {id:625,domain:G,question:"What is a digital certificate's validity period?",options:["The elapsed time since a digital certificate was first issued by the certificate authority, tracked by browsers and TLS libraries to flag excessively old certificates as potentially untrustworthy","The timeframe specified in the certificate during which it is considered valid by relying parties, after which it must be renewed — typically 1 year for DV certificates","The time remaining before an asymmetric private key associated with a TLS certificate reaches its mandatory rotation date per organizational key management policy or industry best practice guidelines","The contracted service window during which a certificate authority commits to responding to certificate status queries, processing revocation requests, and providing technical support to certificate holders"],answer:1,explanation:"Short validity periods (industry moving to 90-day certificates) limit exposure if a key is compromised — an expired certificate is rejected even without revocation.",optionExplanations:["Age since issuance is not embedded in certificates; validity periods are defined by specific notBefore and notAfter timestamps embedded in the certificate structure, independent of how long it has actually been in use.","Certificate validity specifies the 'notBefore' and 'notAfter' dates — clients reject certificates outside this window. The industry is reducing periods to improve revocation effectiveness.","Private key rotation schedules are separate organizational policies; certificate validity periods are cryptographically defined windows embedded in the certificate itself specifying when relying parties should accept it.","CA service level agreements cover support commitments; certificate validity is the cryptographically enforced window embedded in the certificate itself, not the CA's support commitment period."]},
  {id:626,domain:T,question:"What is a SSRF (Server-Side Request Forgery)?",options:["A server-side error condition that occurs when cloud object storage services such as AWS S3 or Azure Blob Storage reject requests with 403 Forbidden responses due to misconfigured bucket policies","A web vulnerability where an attacker causes the server to make HTTP requests to arbitrary URLs — often used to access internal services not exposed to the internet","A server-side access control mechanism that evaluates outbound HTTP requests generated by web application code against an allowlist of permitted destinations before dispatching them to the network","A secure coding design pattern requiring developers to validate all server-initiated HTTP requests against an approved destination allowlist before dispatch, preventing unauthorized outbound connections from backend services"],answer:1,explanation:"SSRF in cloud environments is especially dangerous — attackers can query cloud metadata endpoints (169.254.169.254) to steal IAM credentials, as in the 2019 Capital One breach.",optionExplanations:["Storage service authorization failures are configuration errors; SSRF is a vulnerability class where an attacker manipulates server-side code to cause it to make arbitrary HTTP requests to attacker-specified destinations.","SSRF tricks the server into making requests on the attacker's behalf — bypassing firewalls that block direct external access to internal services, enabling access to internal APIs, metadata services, and administrative interfaces.","Outbound request allowlisting is the mitigation control for SSRF; the vulnerability itself occurs when such controls are absent, allowing attackers to cause servers to make requests to arbitrary internal or external URLs.","Validating server-side requests is the SSRF defense pattern; SSRF the vulnerability describes what happens when this validation is absent and attackers can cause servers to contact arbitrary internal service endpoints."]},
  {id:627,domain:A,question:"What is identity federation?",options:["A consortium of multiple independent organizations that collaborate on shared threat intelligence standards, joint incident response procedures, and mutual security commitments under a formal governance framework","A system allowing users to use a single set of credentials from one organization to access resources in other organizations, based on established trust between identity providers","A process that consolidates multiple separate user accounts from different enterprise directories into a single canonical identity record, eliminating duplicate accounts and simplifying access control administration","A governance approach that synchronizes authorization policies across multiple organizations so all member entities enforce consistent access control decisions for resources shared between partnering companies"],answer:1,explanation:"SAML and OIDC enable federation — a university student uses their university login to access a partner research institution's resources without a separate account.",optionExplanations:["Security information sharing consortia are threat intelligence partnerships; identity federation is specifically the technical capability enabling users to authenticate once and access resources across multiple trusting organizations.","Identity federation trusts the authentication performed by another identity provider — users authenticate once to their home IdP, and federated services accept that authentication assertion.","Identity consolidation or account linking merges duplicate records; identity federation preserves separate identity stores at each organization but establishes trust relationships enabling cross-organizational authentication.","Policy synchronization addresses authorization rules; identity federation addresses authentication — enabling users to present credentials from their home identity provider to access resources at federated partner organizations."]},
  {id:628,domain:O,question:"What is a risk treatment option in cybersecurity?",options:["Psychological support services and employee assistance programs provided to security operations center analysts experiencing burnout, secondary trauma, or stress from handling major data breaches and cyber incidents","The decision about how to handle an identified risk — options include risk acceptance, risk avoidance, risk mitigation (control implementation), and risk transfer (insurance)","A structured incident response procedure developed by the security team that details containment, eradication, and recovery steps for a specific category of confirmed security incident","A risk management philosophy that applies an identical standard set of security controls to every identified risk regardless of the specific likelihood, potential impact, or cost-effectiveness of mitigation"],answer:1,explanation:"Risk transfer (cyber insurance) shifts financial impact; avoidance eliminates the risky activity; mitigation reduces probability or impact; acceptance is conscious tolerance of residual risk.",optionExplanations:["Employee mental health support is an HR function; risk treatment is the formal risk management decision process choosing among risk acceptance, avoidance, mitigation through controls, or transfer through insurance.","After identifying and assessing risks, organizations must decide: accept (tolerate it), avoid (stop the risky activity), mitigate (implement controls to reduce), or transfer (insurance, contracts) the risk.","Incident response plans address active security incidents; risk treatment is the proactive decision-making process for handling identified risks before they materialize into incidents.","Uniform control application ignores risk-based prioritization; risk treatment selects the most appropriate response — accept, avoid, mitigate, or transfer — based on each risk's unique characteristics and business context."]},
  {id:629,domain:T,question:"What is a physical security attack known as shoulder surfing?",options:["Casually glancing at a colleague's desk or monitor to observe what documents or projects they are currently working on during normal office hours","Observing a user's screen, keyboard, or input device without their knowledge to steal passwords, PINs, or sensitive information","A physical penetration technique where an attacker leverages another person's physical body as support to scale a fence, wall, or other physical barrier to gain unauthorized access to secured areas","A physical security attack that tampers with overhead surveillance cameras mounted at shoulder height on building walls to create exploitable blind spots in the physical security monitoring coverage"],answer:1,explanation:"Shoulder surfing is especially effective at ATMs, airports, and coffee shops — privacy screens (polarizing filters), position awareness, and cover when typing PINs are countermeasures.",optionExplanations:["Casual observation of a coworker's work is not a security attack; shoulder surfing involves deliberately and covertly observing a target's screen, keyboard, or input device to steal credentials or sensitive data.","Shoulder surfing directly observes what users type or view — getting close behind a victim at an ATM, sitting adjacent on an airplane, or using binoculars or cameras at distance.","Using someone physically to climb barriers is a different access technique; shoulder surfing is a visual observation attack targeting what a victim types or views on their screen or keypad.","Tampering with surveillance cameras is a physical security attack against the monitoring infrastructure; shoulder surfing is a passive observation technique targeting a victim's screen or keyboard input."]},
  {id:630,domain:G,question:"What is a preimage attack in cryptography?",options:["A technique that generates a low-resolution thumbnail or visual preview of an encrypted file container without decrypting the actual contents, used by content management systems for quick browsing","An attack where given a hash output, the attacker finds an input that produces that hash — defeating hash function security if feasible","An image preprocessing technique applied to data before encryption, converting content into a compressed or normalized format to reduce ciphertext size and improve transmission efficiency over bandwidth-limited channels","An exploit technique that measures precise timing differences between encryption operations on different plaintext inputs to infer information about the key or plaintext through statistical analysis"],answer:1,explanation:"Preimage resistance means finding any input that hashes to a given output should be computationally infeasible — a broken hash function enables forging signatures without the private key.",optionExplanations:["Thumbnail generation for encrypted containers is a file management feature; preimage attacks are cryptanalytic attacks targeting hash functions — finding an input that produces a given hash output.","A preimage attack finds an input m such that hash(m) = target_hash — breaking one-wayness. A second preimage attack finds a different input producing the same hash as a specific known input.","Pre-encryption image compression is a data preparation step; preimage attacks target hash function one-wayness — finding any input whose hash matches a known target hash value without knowing the original input.","Timing-based cryptanalysis is a side-channel attack; preimage attacks are purely mathematical attacks on hash function properties — finding an input that produces a specified hash output without timing observations."]},
];
